        {
            Title = "Gestion Administrative Complète",
            Audience = "StaffAdmin",
            ShortDescription = "Maîtrise du système de gestion du centre",
            Description = "Formation complète pour administrateurs: gestion des utilisateurs, patients, finances et sécurité",
            Level = "Intermédiaire",
            DurationMinutes = 120,
            Tags = new() { "admin", "formation", "système" },
            Steps = new()
            {
                new() { Title = "Accueil et Navigation", Content = "Bienvenue dans Brigade Médicale!\n\n🏥 VOTRE RÔLE:\nComme administrateur, vous êtes responsable de:\n• La gestion globale du centre\n• Les utilisateurs et leurs permissions\n• Les données des patients\n• La sécurité du système\n• Les rapports financiers\n\n🗂️ STRUCTURE DU MENU:\nMenu Principal (gauche):\n1. Tableau de bord - Vue d'ensemble du centre\n2. Patients - Gestion des patients\n3. Consultations - Suivi des visites\n4. Triage Patient - Vital signs (infirmiers)\n5. Laboratoire - Analyses médicales\n6. Pharmacie - Gestion médicaments\n7. Formation - Modules de formation\n8. Utilisateurs - Gestion équipe\n9. Rapports - Analytics et finances\n10. Paramètres - Configuration système\n\n📱 BARRE DE NAVIGATION (haut):\n• Notifications - Alertes système\n• Profil - Vos paramètres personnels\n• Déconnexion - Quitter l'application\n\n💡 CONSEIL: Consultez le tableau de bord chaque matin pour voir l'activité du jour.", Order = 1, Media = new() },
                new() { Title = "Gestion des Utilisateurs et Rôles", Content = "Comprendre et gérer les différents rôles.\n\n👥 LES 7 RÔLES SYSTÈME:\n\n1️⃣ ADMIN\n   • Accès complet au système\n   • Gestion des utilisateurs\n   • Configuration système\n   • Accès aux données sensibles\n   • Exemple: Directeur du centre\n\n2️⃣ ACCUEIL\n   • Enregistrement des patients\n   • Gestion des files d'attente\n   • Communication patient\n   • Collecte des paiements\n   • Exemple: Réceptionniste\n\n3️⃣ MEDECIN\n   • Consultation des patients\n   • Prescription de médicaments\n   • Diagnostic et notes\n   • Demande d'analyses\n   • Exemple: Médecin généraliste\n\n4️⃣ LABORANTIN\n   • Gestion des analyses\n   • Résultats de laboratoire\n   • Équipement et stocks\n   • Protocoles de sécurité\n   • Exemple: Technicien de laboratoire\n\n5️⃣ PHARMACIEN\n   • Gestion des stocks médicaments\n   • Dispensation prescriptions\n   • Interactions médicamenteuses\n   • Inventaire\n   • Exemple: Chef pharmacie\n\n6️⃣ SUPERVISEUR\n   • Supervision d'équipe\n   • Rapports de qualité\n   • KPIs du centre\n   • Validation consultations\n   • Exemple: Chef de département\n\n7️⃣ INFIRMIER\n   • Triage patients\n   • Enregistrement vitaux\n   • Soins infirmiers\n   • Support médecin\n   • Exemple: Infirmière\n\n⚙️ AJOUTER UN NOUVEL UTILISATEUR:\n1. Menu 'Utilisateurs' → 'Nouvel utilisateur'\n2. Remplissez:\n   • Nom complet\n   • Email (important - utilisé pour connexion)\n   • Sélectionner le rôle\n3. Cliquez 'Créer'\n4. L'utilisateur reçoit un email avec un lien pour initialiser son mot de passe\n\n🔐 SÉCURITÉ RÔLES:\n✓ Assignez toujours le rôle minimum requis\n✓ Ne donnez jamais ADMIN à moins que nécessaire\n✓ Révoquez les accès immédiatement si départ\n✓ Vérifiez régulièrement les permissions\n✗ Ne jamais partager les accès ADMIN\n✗ Ne pas créer des \"super utilisateurs\"\n✗ Ne pas ignorer les audits de sécurité", Order = 2, Media = new() },
                new() { Title = "Enregistrement Patient - Procédure Complète", Content = "L'enregistrement correct est fondamental pour la qualité des soins.\n\n📝 ÉTAPES D'ENREGISTREMENT:\n\nÉTAPE 1: INFORMATIONS DE BASE\n□ Nom complet (exactement comme ID)\n□ Prénoms\n□ Date de naissance (DD/MM/YYYY)\n□ Lieu de naissance\n□ Sexe (M/F/Autre)\n\nÉTAPE 2: CONTACT\n□ Numéro téléphone principal\n□ Numéro téléphone alternatif (optionnel)\n□ Email (optionnel)\n\nÉTAPE 3: ADRESSE\n□ Adresse complète\n□ Quartier/Zone\n□ Ville\n□ Code postal\n\nÉTAPE 4: SITUATION MÉDICALE (Important!)\n□ Groupe sanguin\n□ Allergies (médicaments, aliments)\n□ Maladies chroniques\n□ Antécédents chirurgicaux\n\nÉTAPE 5: INFORMATION D'URGENCE\n□ Personne à contacter en urgence\n□ Numéro de cette personne\n□ Relation (parent, conjoint, ami)\n\nÉTAPE 6: CONTEXTE (Optionnel)\n□ Secteur géographique\n□ Secteur d'église (si applicable)\n□ Notes spéciales\n\n✅ RÉSULTAT APRÈS ENREGISTREMENT:\nLe patient reçoit automatiquement:\n• Numéro patient unique: BM-YYYY-XXXXX (exemple: BM-2026-00001)\n• Code QR personnel (pour visites futures)\n• Accès au carnet patient en ligne\n• Email de confirmation\n\n⚠️ POINTS CRITIQUES:\n⚠️ Le numéro patient EST PERMANENT - ne peut pas changer\n⚠️ Les allergies DOIVENT être enregistrées (sécurité)\n⚠️ Vérifiez l'orthographe 2 fois (nom surtout)\n⚠️ Date naissance = très important (âge des médicaments)\n⚠️ Toujours demander le groupe sanguin\n\n🔍 VÉRIFICATIONS AVANT DE VALIDER:\n□ Tous les champs obligatoires remplis?\n□ Pas de doublons existants?\n□ Informations sensibles correctes?\n□ Numéro de téléphone valide?\n□ Adresse complète?\n\n💡 CONSEIL: Prenez le temps pour bien enregistrer. C'est la base de tous les soins futurs.", Order = 3, Media = new() },
                new() { Title = "Consultation et Suivi Patient", Content = "Accédez et gérez l'historique complet des consultations.\n\n🏥 VISUALISER LES CONSULTATIONS:\n1. Menu 'Consultations'\n2. Filtrage avancé:\n   • Par patient (recherche)\n   • Par date (entre deux dates)\n   • Par médecin responsable\n   • Par type (diagnostic, suivi, urgence)\n   • Par statut (complète, en cours, annulée)\n3. Cliquez sur une consultation pour le détail complet\n\n📋 INFORMATIONS DANS UNE CONSULTATION:\n\nVue d'ensemble:\n• Numéro patient et nom\n• Date/heure de la consultation\n• Médecin responsable\n• Type de visite\n• Durée\n\nDétails médicaux:\n• Plainte principale du patient\n• Historique relevant\n• Signes vitaux enregistrés\n• Examen physique (notes)\n• Diagnostic\n• Pronostic\n\nActions prises:\n• Prescriptions (médicaments)\n• Analyses demandées (labo)\n• Imagerie demandée\n• Procédures effectuées\n• Renvois spécialistes\n\nSuivi:\n• Prochain rendez-vous proposé\n• Instructions pour le patient\n• Notes privées (équipe)\n• Documents attachés (résultats labo, images)\n\n📊 RAPPORTS CONSULTATION:\n1. Cliquez 'Générer PDF' pour exporter\n2. Format professionnel pour patient\n3. Ou 'Exporter Excel' pour archivage\n4. Partagez par email si autorisé\n\n⏱️ DÉLAIS IMPORTANTS:\n• Résultats labo: Généralement 24-48h\n• Validation consultation: Avant fin du jour (infirmière)\n• Prescription: Doit être validée (pharmacien)\n• Suivi: Dépend du diagnostic\n\n🔒 SÉCURITÉ DONNÉES:\n✓ Chaque consultation est tracée\n✓ Qui a consulté quelle donnée et quand\n✓ Impossible de supprimer une consultation\n✓ Les modifications laissent une trace\n\n💡 CONSEIL: Consultez régulièrement les \"consultations en attente\" de validation pour assurer la qualité.", Order = 4, Media = new() },
                new() { Title = "Gestion Financière et Paiements", Content = "Suivi complet de la situation financière du centre.\n\n💰 MODULE FINANCES:\n\n1️⃣ ENREGISTRER UN PAIEMENT:\n   • Menu 'Consultations' ou 'Patients'\n   • Sélectionner le patient\n   • Cliquez 'Ajouter paiement'\n   • Montant\n   • Mode (espèces, chèque, mobile money, carte)\n   • Référence (numéro reçu)\n   • Date\n   • Valider\n\n2️⃣ VOIR L'HISTORIQUE DE PAIEMENTS:\n   • Menu 'Rapports' → 'Finances'\n   • Sélectionner:\n     - Période (dates)\n     - Mode de paiement\n     - Statut (payé, partiel, impayé)\n   • Visualiser tous les transactions\n\n3️⃣ IMPAYÉS - Gestion des dettes:\n   • Menu 'Rapports' → 'Patients en impayé'\n   • Liste des patients avec solde négatif\n   • Montant total dû\n   • Nombre de jours de retard\n   • Historique de relances\n   • Cliquez pour voir détails et relancer\n\n4️⃣ RAPPORTS FINANCIERS:\n   • Menu 'Rapports' → 'Finances'\n   • Choisir période\n   • Générer rapport:\n     - Total collecté\n     - Nombre de transactions\n     - Montant moyen par consultation\n     - Patients nouveaux vs retour\n     - Tendance (hausse/baisse)\n     - Prévision mois prochain\n   • Exporter PDF ou Excel\n\n📊 INDICATEURS CLÉS (KPIs):\n• Taux de recouvrement = Payé / Total dû\n• Montant moyen par patient\n• Nombre de transactions/jour\n• Impayés en % du chiffre d'affaires\n\n🔍 AUDIT FINANCIER:\nChaque transaction inclut:\n• Date et heure exacte\n• Utilisateur qui a enregistré\n• Montant et mode\n• Patient et consultation\n• Approbation superviseur\n• Impossible à modifier après validation\n\n💡 RECOMMANDATIONS:\n✓ Enregistrez chaque paiement le jour même\n✓ Validez les impayés mensuellement\n✓ Générez un rapport hebdomadaire\n✓ Communiquez les arriérés au superviseur\n✓ Mettez en place un plan de relance\n\n⚠️ POLITIQUES:\n• Les patients très en retard ne peuvent pas poursuivre\n• Les consultations sans paiement doivent être signalées\n• Les écarts non expliqués doivent être justifiés\n• Les chiffres doivent concorder avec la caisse", Order = 5, Media = new() },
                new() { Title = "Sécurité, Sauvegarde et Maintenance", Content = "Maintenez la sécurité et l'intégrité des données.\n\n🔐 SÉCURITÉ SYSTÈME:\n\nMots de passe:\n✓ Minimum 12 caractères\n✓ Mélange: majuscules + minuscules + chiffres + symboles\n✓ Changement tous les 3 mois\n✓ Jamais la même que les 5 précédents\n✓ Ne jamais partager\n✗ Ne jamais écrire sur papier\n✗ Ne jamais utiliser noms proches\n\nAccès:\n✓ Déconnectez-vous toujours en quittant\n✓ Pas d'accès multi-utilisateur sur un compte\n✓ Verrouillez l'écran si absent 5min\n✓ Utilisez les VPN en wifi public\n✓ Signalez tout accès suspecte\n\n💾 SAUVEGARDES:\n\nAutomatiques:\n• Tous les jours à minuit UTC\n• Sauvegarde complète base de données\n• Sauvegarde fichiers patients\n• Sauvegarde logs d'activité\n• Vérification automatique (OK/KO)\n\nManuel (vous):\n• Téléchargez mensuellement les archives\n• Stockez sur disque externe\n• Gardez 3 mois d'historique local\n• Testez la restauration (1x/trimestre)\n\nRécupération:\n• Si perte de données:\n  1. Contactez support immédiatement\n  2. Arrêtez toute utilisation\n  3. Fournissez date/heure de perte\n  4. Équipe IT restaure depuis sauvegarde\n  5. Maximum 24h de perte de données\n\n⚙️ MAINTENANCE SYSTÈME:\n\nMises à jour:\n• Mercredi 2h du matin (prévu)\n• Durée: 30-60 minutes\n• Système indisponible pendant\n• Notification 24h avant\n• Pas d'impact sur données\n\nPatches de sécurité:\n• Appliqué dès que disponible\n• Peut être urgent (critique)\n• Redémarrage requis parfois\n• Équipe IT vous prévient\n\n👁️ LOGS D'ACTIVITÉ:\n\nQui consulte quoi:\n• Menu 'Paramètres' → 'Journaux activité'\n• Filtrer par:\n  - Utilisateur\n  - Action (lecture, modification, suppression)\n  - Entité (patient, consultation)\n  - Date/heure\n• Chaque action tracée\n• Immuable (impossible de modifier)\n\nCe qu'on voit:\n• 16h15 - Admin1 - Consulté dossier patient BM-2026-00001\n• 16:17 - Medecin1 - Modifié diagnostic consultation #456\n• 16:20 - Accueil1 - Enregistré paiement de 50000 FCFA\n\n🚨 INCIDENTS SÉCURITÉ:\n\nSi vous suspectez:\n• Accès non autorisé\n• Données modifiées sans raison\n• Tentatives de connexion échouées répétées\n• Ralentissement suspect du système\n\nFAIRES:\n1. Signalez immédiatement à l'admin local\n2. Déconnectez-vous\n3. Contactez support: support@brigademédicale.ci\n4. Fourniture logs et détails\n\n🆘 SUPPORT TECHNIQUE:\n• Email: support@brigademédicale.ci\n• Téléphone: +225 XX XX XX XX\n• Chat dans l'app: 'Aide' → 'Support'\n• Réponse: 30 min (critique), 2h (urgent), 8h (normal)\n\n💡 CHECKLIST MENSUELLE:\n□ Changez votre mot de passe\n□ Vérifiez le log d'activité pour accès anormal\n□ Téléchargez une sauvegarde\n□ Revoyez les utilisateurs actifs\n□ Vérifiez les rapports de sécurité\n□ Communiquez avec l'équipe IT", Order = 6, Media = new() },
                new() { Title = "Bonnes Pratiques et Excellence", Content = "Devenir excellent administrateur du centre.\n\n🏆 EXCELLENCE ADMINISTRATIVE:\n\n☑️ CHECKLIST QUOTIDIENNE (5-10 min):\n08h00:\n  □ Vérifier tableau de bord → statistiques du jour\n  □ Consulter les alertes système\n  □ Valider les consultations de la veille\n  □ Vérifier les paiements enregistrés\n\n12h00:\n  □ Point mi-journée (consultations en cours)\n  □ Vérifier les pharmacies (stocks disponibles)\n  □ Voir labo (résultats disponibles)\n\n17h00:\n  □ Voir les consultations du jour complétées\n  □ Valider les analyses pendant la journée\n  □ Réconcilier les paiements\n  □ Signaler tout problème technique\n\n18h00:\n  □ Générer rapport end-of-day\n  □ Archiver documents importants\n  □ Vérifier les emails non traités\n\n☑️ CHECKLIST HEBDOMADAIRE:\n Lundi 9h:\n  □ Rapport financier de la semaine\n  □ KPIs du centre (patients, consultations)\n  □ Activité par médecin\n  □ Impayés en retard\n  □ Problèmes à résoudre\n\n☑️ CHECKLIST MENSUELLE:\n 1er du mois:\n  □ Analyse financière complète\n  □ Rapports de performance\n  □ Prévisions budget mois suivant\n  □ Audit logs d'activité\n  □ Changement mot de passe\n  □ Télécharger sauvegarde\n  □ Audit sécurité\n  □ Formation du personnel\n\n🎯 PRINCIPES FONDAMENTAUX:\n\n1️⃣ QUALITÉ AVANT VITESSE\n✓ Prenez le temps pour bien enregistrer\n✓ Vérifiez deux fois les données sensibles\n✓ Les erreurs coûtent cher (temps + crédibilité)\n\n2️⃣ TRANSPARENCE\n✓ Tous les chiffres doivent être justifiables\n✓ Documentez vos décisions\n✓ Communiquez les problèmes rapidement\n✓ Pas d'arrangement \"pour arranger\"\n\n3️⃣ SÉCURITÉ TOUJOURS\n✓ Les données des patients sont confidentielles\n✓ Ne partagez JAMAIS les accès\n✓ Signalez tout incident immédiatement\n✓ Respectez les protocoles de sécurité\n\n4️⃣ ÉQUIPE D'ABORD\n✓ Aidez les autres utilisateurs\n✓ Formez les nouvelles recrues\n✓ Créez une culture de qualité\n✓ Soyez modèle de comportement\n\n5️⃣ AMÉLIORATION CONTINUE\n✓ Écoutez les feedback des utilisateurs\n✓ Proposez des améliorations\n✓ Testez les nouvelles fonctionnalités\n✓ Partagez les bonnes pratiques\n\n🚀 DÉVELOPPER L'EXCELLENCE:\n\nPour devenir excellent:\n1. Maîtrisez tous les modules de formation\n2. Pratiquez régulièrement les workflows\n3. Aidez les autres à bien utiliser le système\n4. Proposez des améliorations au superviseur\n5. Restez à jour avec les mises à jour\n\n📊 MESURER VOTRE IMPACT:\n\nBons signes:\n✓ Zéro erreur dans les enregistrements\n✓ Taux de recouvrement > 95%\n✓ Feedback positif des utilisateurs\n✓ Système stable sans incidents\n✓ Rapport financier à jour\n✓ Formation équipe complète\n\nDéfis à relever:\n⚠️ Enregistrements incomplets\n⚠️ Erreurs de saisie récurrentes\n⚠️ Impayés croissants\n⚠️ Utilisateurs non formés\n⚠️ Rapports tardifs\n\n💡 CONSEIL FINAL:\n\"Un bon administrateur n'est pas celui qui fait tout,\nmais celui qui fait en sorte que tout fonctionne bien.\"\n\nVotre rôle = Activateur de qualité et gardien de l'intégrité.", Order = 7, Media = new() }
            },
