    public static List<CreateTrainingModuleDto> GetAccueilModules() => new()
    {
        new()
        {
            Title = "Accueil et Enregistrement Patient",
            Audience = "StaffAccueil",
            ShortDescription = "Maîtriser l'accueil professionnel et l'enregistrement des patients",
            Description = "Formation complète pour le personnel d'accueil: communication, enregistrement, gestion des files d'attente et paiements",
            Level = "Intermédiaire",
            DurationMinutes = 90,
            Tags = new() { "accueil", "formation", "patient" },
            Steps = new()
            {
                new() { Title = "Rôle et Responsabilités", Content = "Bienvenue! Vous êtes la PREMIÈRE IMPRESSION du centre.\n\n🎯 VOTRE MISSION:\n• Accueillir chaque patient avec respect et professionnalisme\n• Enregistrer les nouveaux patients\n• Gérer les files d'attente efficacement\n• Recueillir les paiements\n• Répondre aux questions de base\n• Diriger les patients vers les bons services\n\n👥 PATIENTS QUE VOUS VERREZ:\n• Nouveaux patients (premiers rendez-vous)\n• Patients revenus (consultations de suivi)\n• Familles (accompagnants)\n• Patients urgents (à priorité)\n\n💼 COMPÉTENCES CLÉS:\n✓ Écoute active et empathie\n✓ Organisation et rigueur\n✓ Gestion du stress\n✓ Communication claire\n✓ Honnêteté et intégrité\n✓ Rapidité sans sacrifier la qualité\n\n⏰ VOTRE JOURNÉE:\n• 07h30 - Arrivée, préparation du poste\n• 08h00 - Ouverture, accueil patients\n• 12h00 - Pause (30 min)\n• 12h30 - Service continue\n• 17h00 - Fermeture, nettoyage, rapports\n• 17h30 - Fin\n\n💡 CONSEIL: Soyez toujours souriant. Même si vous êtes occupé, un sourire fait la différence!", Order = 1, Media = new() },
                new() { Title = "Communication Avec les Patients", Content = "L'accueil c'est 80% communication, 20% technique.\n\n💬 PRINCIPES DE COMMUNICATION:\n\n1️⃣ SALUTATION:\n• Levez-vous si possible\n• Sourire sincère\n• Contact visuel\n• \"Bonjour Madame/Monsieur, bienvenue!\"\n• Présentez-vous: \"Je m'appelle [nom]\"\n\n2️⃣ ÉCOUTE ACTIVE:\n• Écoutez complètement (pas d'interruption)\n• Posez des questions si nécessaire\n• Montrez de l'intérêt (hochez la tête)\n• Résumez ce que vous comprenez\n• Validez leurs préoccupations\n\n3️⃣ RÉPONSES APPROPRIÉES:\n• Soyez honnête (ne promettez pas ce que vous ne savez pas)\n• Si vous ne savez pas, dites \"Je vais vérifier\"\n• Expliquez en termes simples\n• Soyez rassurant\n• Donnez des informations claires\n\n4️⃣ GESTION DE L'IMPATIENCE:\nLe patient est stressé ou en douleur:\n• Reconnaître: \"Je comprends que vous êtes préoccupé\"\n• Rassurer: \"Nous allons vous aider rapidement\"\n• Informer: \"Vous verrez le médecin dans environ X minutes\"\n• Rester calme: Ne pas montrer du stress\n\n5️⃣ LANGUE:\n• Parlez clairement\n• Pas d'argot ou d'humour lourd\n• Adapté au niveau de compréhension\n• Si différente langue - trouvez quelqu'un qui parle\n• Écrivez si nécessaire (problème d'audition)\n\n🚫 À ÉVITER:\n✗ Être impatient ou brusque\n✗ Utiliser votre téléphone en parlant au patient\n✗ Parler mal des collègues\n✗ Donner des conseils médicaux\n✗ Promettre quoi que ce soit que vous ne savez pas\n✗ Montrer de la fatigue ou du dégoût\n✗ Problèmes personnels au travail\n\n✓ À FAIRE:\n✓ Maintenir la confidentialité\n✓ Être patient même si c'est votre 100ème question\n✓ Poser clarification si nécessaire\n✓ Diriger vers le bon service\n✓ Suivre le flux naturel\n\n👨‍👩‍👧 TYPES DE PATIENTS:\n\nPatient calme:\n• Traitement normal et efficace\n\nPatient stressé:\n• Extra patience, rassurant, informatif\n\nPatient âgé:\n• Parlez plus fort, plus lent, respectueux\n\nPatient enfant:\n• Parlez aussi aux parents, soyez amical\n\nPatient en douleur:\n• Essayez de l'asseoir, chercher aide infirmière\n\nPatient en colère:\n• Rester calme, ne pas prendre personnellement\n• Écouter, comprendre, escalader si nécessaire\n\n💡 CONSEIL: Traitez chaque patient comme si c'était votre mère ou père. La qualité de l'accueil détermine la satisfaction globale.", Order = 2, Media = new() },
                new() { Title = "Enregistrement Nouveau Patient", Content = "Processus d'enregistrement d'un nouveau patient.\n\n📋 AVANT LE PATIENT:\n□ Préparez le formulaire d'enregistrement\n□ Préparez le stylo (bleu ou noir)\n□ Vérifiez l'écran de l'ordinateur\n□ Zone de travail propre et organisée\n\n📝 ÉTAPES D'ENREGISTREMENT:\n\nÉTAPE 1: VÉRIFIER LE STATUT\n• \"C'est votre première visite?\"\n• Oui → Continuer enregistrement complet\n• Non → Vérifier dans le système (voir étape section)\n\nÉTAPE 2: FORMULAIRE D'ENREGISTREMENT\nRemplissez chaque section:\n□ Nom complet (comme sur l'ID)\n□ Prénoms\n□ Date de naissance (DD/MM/YYYY)\n□ Lieu de naissance\n□ Sexe (M/F/Autre)\n□ Numéro d'ID national (si disponible)\n\nÉTAPE 3: CONTACT\n□ Téléphone principal\n□ Téléphone alternatif (optionnel)\n□ Email (optionnel)\n□ Adresse\n□ Ville\n\nÉTAPE 4: INFORMATIONS MÉDICALES (Critique!)\n□ \"Avez-vous un groupe sanguin connu?\"\n□ \"Des allergies aux médicaments?\"\n□ \"Des maladies chroniques? (tension, diabète, etc.)\"\n□ \"Avez-vous subi des opérations?\"\n\nÉTAPE 5: PERSONNE À CONTACTER EN URGENCE\n□ Nom\n□ Numéro de téléphone\n□ Relation (parent, conjoint, ami)\n\nÉTAPE 6: CONTEXTE (Optionnel)\n□ Secteur géographique\n□ Secteur d'église\n□ Notes spéciales\n\nÉTAPE 7: CONFIRMATION\n• Récapituer les informations au patient\n• \"Vérifiez si c'est correct\"\n• Corrections si nécessaire\n• Patient signe ou initialise\n\nÉTAPE 8: SYSTÈME\n• Rentrer les données dans le système\n• Le numéro patient génère automatiquement: BM-YYYY-XXXXX\n• Imprimer le QR code\n• Imprimer le carnet patient\n\n✅ APRÈS ENREGISTREMENT:\n□ Remerciez le patient\n□ Donnez le numéro patient (à mémoriser)\n□ Donnez le QR code (à garder)\n□ Donnez le carnet (instruits comment l'utiliser)\n□ Expliquez les prochaines étapes\n□ Dirigez vers l'infirmière pour le triage\n\n⚠️ POINTS CRITIQUES:\n⚠️ Demandez clairement l'orthographe du nom (deux fois!)\n⚠️ Allergies DOIVENT être enregistrées (aller vérifier si pas sûr)\n⚠️ Groupe sanguin - insistez un peu\n⚠️ La date de naissance doit être exacte (années)\n⚠️ Ne pas enregistrer quelqu'un sans info de contact d'urgence\n\n🔍 DOUBLONS - Comment vérifier:\n• Nouveau patient donne le nom\n• Cherchez dans le système: Nom + Prénom\n• Vérifiez aussi par date de naissance\n• Si trouvé: \"Ah, vous avez déjà visité le 10 janvier?\"\n• Si doute: Demander \"Avez-vous un carnet/QR code?\"\n\n💡 CONSEIL: L'enregistrement doit prendre 5-10 minutes. Plus rapide = risque d'oubli. Plus lent = file s'allonge. Cherchez l'équilibre!", Order = 3, Media = new() },
                new() { Title = "Gestion de la File d'Attente", Content = "Maintenir un flux efficace sans surcharger les services.\n\n📊 COMPRENDRE LA FILE:\n\n• Patients arrivent = Enregistrement\n• Enregistrement = Triage (infirmière)\n• Triage = Salle d'attente\n• Appel = Consultation médicale\n• Après consultation = Paiement\n• Après paiement = Départ ou pharmacie\n\n⏱️ TEMPS MOYENS:\n• Enregistrement: 5-10 min par patient\n• Triage: 3-5 min\n• Attente consultation: 15-30 min (selon urgence)\n• Consultation: 10-20 min\n• Paiement: 2-3 min\n• Total par patient: 45-90 min\n\n👁️ VOTRE RÔLE DANS LA FILE:\n\n1️⃣ DIRECTION:\n• Après enregistrement: \"L'infirmière vous attend à droite\"\n• Expliquez où aller\n• Assurez-vous qu'ils comprennent\n\n2️⃣ GESTION DU FLUX:\n• Enregistrez rapidement et efficacement\n• Pas de distractions pendant l'enregistrement\n• Si file s'allonge > 10 patients: Appelez aide infirmière\n• Priorité: Enfants, personnes âgées, urgences\n\n3️⃣ ATTENTE PATIENTS:\n• Siège confortable et propre\n• Pas de bruit excessif\n• Climatisation fonctionnelle\n• Eau gratuite disponible (si possible)\n• Info sur le temps d'attente estimé\n\n4️⃣ ACCÉLÉRER LE FLUX:\n• Ne pas bavarder pendant travail\n• Pré-remplissez les formulaires si possible\n• Groupez les enregistrements par médecin (si plusieurs)\n• Appelez vite pour consultation\n• Validez les paiements rapidement\n\n⚠️ SITUATIONS DIFFICILES:\n\nPatient impatient:\n• Reconnaître: \"Je sais que vous attendez longtemps\"\n• Informer: \"Vous serez appelé dans 5 minutes\"\n• Rester professionnel: Ne pas s'énerver\n\nFile très longue:\n• Prévenez le superviseur\n• Appelez aide infirmière\n• Organisez en priorité (urgents d'abord)\n\nPatient sans rendez-vous:\n• Vérifiez qui est disponible\n• Si complet: Proposez horaire suivant\n• Si urgent: Escaladez au superviseur\n\n🎯 OBJECTIFS DE LA FILE:\n✓ Patients vus rapidement\n✓ Qualité n'est pas sacrifiée\n✓ Pas de chaos ou bousculades\n✓ Chaque patient se sent écouté\n✓ Flux fluide et prévisible\n\n💡 CONSEIL: Une file courte est signe d'efficacité. Travaillez avec l'infirmière pour maintenir le flux équilibré.", Order = 4, Media = new() },
                new() { Title = "Paiements et Finances", Content = "Collecter les paiements avec professionnalisme et exactitude.\n\n💰 TYPES DE PAIEMENTS:\n\n1. ESPÈCES:\n   • Accepté toujours\n   • Vérifiez les billets (faux?)\n   • Donnez monnaie exacte\n   • Comptez l'argent à deux (vous + patient)\n   • Recepissé obligatoire\n\n2. CHÈQUE:\n   • Vérifiez l'endossement\n   • Vérifiez date et montant\n   • Vérifiez signature\n   • Enregistrez le numéro de chèque\n   • Demandez ID si doute\n\n3. MOBILE MONEY (Orange Money, MTN Money):\n   • Demandez le numéro\n   • Entrez montant\n   • Patient confirme\n   • Vous recevez la confirmation\n   • Enregistrez l'ID transaction\n\n4. CARTE BANCAIRE:\n   • Passez la carte dans le lecteur\n   • Patient entre le PIN (vous ne regardez pas)\n   • Imprimez le reçu\n   • Donnez la carte + reçu\n\n📋 AVANT DE TRAITER LE PAIEMENT:\n□ Vérifiez le montant dû (consultation + analyses?)\n□ Vérifiez si patient a des crédits (précédentes visites)\n□ Vérifiez si réductions (enfant, étudiant, personnel)\n□ Confirmez le montant final au patient\n\n✅ TRAITEMENT DU PAIEMENT:\n1. Dites le montant clairement\n2. Acceptez la forme de paiement\n3. Traitez correctement (voir types ci-dessus)\n4. Enregistrez dans le système:\n   • Date et heure\n   • Montant\n   • Mode (espèces, chèque, mobile, carte)\n   • Référence (numéro)\n   • Patient\n5. Donnez reçu au patient\n6. Dites \"Merci, bonne journée\"\n\n🧮 CALCULS COMMUNS:\n• Consultation de base: Exemple 15 000 FCFA\n• Analyses labo: Selon type (10-50k FCFA)\n• Médicaments: Selon ordonnance\n• Total = Tous les services rendus\n\n⚠️ SITUATIONS DÉLICATES:\n\nPatient sans assez d'argent:\n• Calme: \"Aucun problème\"\n• Solution 1: Paiement partiel (moitié maintenant, moitié plus tard)\n• Solution 2: Parler au superviseur (réductions?)\n• Solution 3: Reprogrammer pour plus tard\n• JAMAIS: Refuser les soins ou être brusque\n\nPatient qui conteste le montant:\n• Rester calme\n• Expliquer les charges (consultation + analyses)\n• Montrer le détail sur système\n• Si doute: Appeler superviseur\n\nMonnaie manquante:\n• Comptez deux fois\n• Si vraiment manquant: Dire au superviseur\n• Ne jamais accuser le patient\n• Vérifier si vous avez fait erreur\n\n🔐 SÉCURITÉ CAISSE:\n✓ Gardez l'argent sécurisé\n✓ Caisse fermée quand vous partez\n✓ Comptage en fin de journée\n✓ Enregistrement des totaux\n✓ Signature obligatoire\n✓ Discrétion sur les montants\n\n💡 CONSEIL: L'argent du patient est une responsabilité. Traitez-le avec respect et exactitude. Les erreurs détruisent la confiance.", Order = 5, Media = new() },
                new() { Title = "Problèmes Communs et Solutions", Content = "Comment gérer les défis quotidiens.\n\n🆘 PROBLÈME: Patient cherche un médecin spécifique\nSOLUTION:\n1. Vérifiez l'horaire\n2. Si disponible: \"Le Dr. [nom] est disponible maintenant\"\n3. Si pas disponible: \"Il revient à 14h\" ou proposer autre médecin\n4. Si urgent: \"Laissez-moi chercher qui est disponible\"\n\n🆘 PROBLÈME: Patient demande où est la toilette\nSOLUTION:\n1. Levez-vous et montrez (ne pas juste indiquer)\n2. Expliquez: \"À gauche, au couloir\"\n3. Assurez-vous qu'il comprenne\n\n🆘 PROBLÈME: Deux patients arrivent en même temps\nSOLUTION:\n1. \"Bienvenue! Un moment s'il vous plaît\"\n2. Demandez qui est arrivé en premier\n3. Enregistrez dans l'ordre d'arrivée\n4. Efficacité: 2 mins par patient possible\n\n🆘 PROBLÈME: Patient perd son carnet/QR code\nSOLUTION:\n1. Pas de panique: \"Pas de problème\"\n2. Demandez: \"Souvenez-vous de votre numéro patient?\"\n3. Cherchez dans système par nom + date de naissance\n4. Imprimez nouveau QR code\n5. Dites: \"Gardez précieusement cette fois\"\n\n🆘 PROBLÈME: Quelqu'un arrive sans papiers\nSOLUTION:\n1. \"Vous pouvez être soigné\"\n2. Enregistrez avec nom et téléphone\n3. Dites: \"Apportez vos papiers à la prochaine visite\"\n4. Infirmière notera les manques\n\n🆘 PROBLÈME: Système informatique en panne\nSOLUTION:\n1. Enregistrement manuel sur formulaire papier\n2. Transcrivez dans système une fois réparé\n3. Prévenez le superviseur\n4. Continuez le service\n\n🆘 PROBLÈME: Patient très malade/urgence\nSOLUTION:\n1. Appelez immédiatement l'infirmière/médecin\n2. Demandez au patient: \"Pouvez-vous vous asseoir?\"\n3. Informez: \"Vous serez vu en priorité\"\n4. Restez calme et rassurant\n5. Ne laissez pas seul\n\n🆘 PROBLÈME: Plainte ou mécontentement\nSOLUTION:\n1. Écoutez complètement\n2. Dites: \"Je comprends votre frustration\"\n3. Demandez: \"Comment puis-je aider?\"\n4. Escaladez au superviseur si nécessaire\n5. Documentez la plainte\n\n🆘 PROBLÈME: Trop d'appels téléphoniques\nSOLUTION:\n1. Si occupé avec patient: \"Un moment, je vous rappelle\"\n2. Prenez message avec: Nom, numéro, raison\n3. Transférez au bon département\n4. Si absent: \"Rappelez ce numéro\"\n5. Soyez professionnel au téléphone aussi\n\n🆘 PROBLÈME: Conflit avec collègue\nSOLUTION:\n1. Parlez en privé (pas devant patients)\n2. Restez professionnel\n3. Cherchez la solution ensemble\n4. Si grave: Informez le superviseur\n5. Fini après: Redevient normal\n\n💡 CONSEIL: Chaque problème est une opportunité de montrer votre professionnalisme. Restez calme et cherchez la solution!", Order = 6, Media = new() },
                new() { Title = "Excellence et Développement", Content = "Devenir excellent professionnel d'accueil.\n\n🏆 MARQUES D'UN BON ACCUEIL:\n\n✓ Patients sourient en partant\n✓ Pas de plaintes\n✓ File courte et ordonnée\n✓ Erreurs d'enregistrement = rare\n✓ Collègues apprécient votre travail\n✓ Superviseur vous fait confiance\n✓ Patients demandent à vous revoir\n\n☑️ CHECKLIST QUOTIDIENNE:\n08h00:\n  □ Arrivée 10 min avant\n  □ Poste de travail propre et organisé\n  □ Formulaires à proximité\n  □ Stylos qui fonctionnent\n  □ Système informatique testé\n\n10h00:\n  □ Comptage de caisse (si gérez l'argent)\n  □ Vérifier qu'aucune file d'attente massive\n\n12h00:\n  □ Pause (notez les heures)\n  □ Retour: Réchauffement\n\n15h00:\n  □ Vérifier dossiers en attente\n  □ Antennage: Patients prêts à partir?\n\n17h00:\n  □ Enregistrement des derniers patients\n  □ Fermeture poste\n  □ Comptage final (si argent)\n  □ Rapport au superviseur\n\n☑️ COMPÉTENCES À DÉVELOPPER:\n\n1. DACTYLOGRAPHIE:\n   • Plus rapide = meilleur flux\n   • Pratquez le soir\n   • Visez 40+ mots/minute\n\n2. GESTION DU STRESS:\n   • Respiration profonde (inhale 4s, exhale 4s)\n   • Ne pas prendre personnellement\n   • Pause si très stressé\n   • Parlez au superviseur\n\n3. EMPATHIE:\n   • Mettez-vous à la place du patient\n   • Écoutez vraiment\n   • Montrez de l'intérêt\n   • Validez leurs sentiments\n\n4. RAPIDITÉ SANS ERREUR:\n   • Vérifiez 2x avant validation\n   • Mais pas trop lent\n   • Efficacité = Art\n\n5. CONNAISSANCE DU SYSTÈME:\n   • Apprenez tous les menus\n   • Troubleshoot basique\n   • Formez les nouveaux\n\n🎯 OBJECTIFS À ATTEINDRE:\n\nMois 1:\n✓ Enregistrement fluide sans erreur\n✓ Patients se sentent bienvenue\n✓ Zéro plainte d'accueil\n✓ File moyenne < 8 patients\n✓ Superviseur satisfait\n\nMois 3:\n✓ Expert en système\n✓ Aidez les collègues\n✓ Suggestions d'amélioration proposées\n✓ Patients reconnaissent votre nom\n✓ Vous formez les nouveaux\n\nMois 6+:\n✓ Chef d'équipe informel\n✓ Meilleure efficacité d'accueil\n✓ Zéro erreurs d'enregistrement\n✓ Patients très satisfaits\n✓ Prêt pour superviseur si promotion\n\n💡 CITATIONS INSPIRANTES:\n\"Chaque patient se souviendra de comment vous les avez traités, pas de ce que vous avez dit.\"\n\"L'accueil c'est la première et dernière impression. Faites-la compter.\"\n\"Un sourire ne coûte rien, mais crée beaucoup de valeur.\"\n\n🌟 VOTRE IMPACT:\nVous n'êtes pas \"juste\" accueil. Vous êtes:\n• Médecin de première ligne (écoute)\n• Ambassadeur du centre (première impression)\n• Gestionnaire de crise (calme sous pression)\n• Chef d'équipe (direction du flux)\n• Gardien de qualité (exactitude)\n\nVotre travail détermine la satisfaction de TOUS les patients. C'est fondamental!", Order = 7, Media = new() }
            },
            Quiz = new()
            {
                new() { Question = "Quelle est la première chose à faire quand un patient arrive?", Options = new() { "Lui donner le formulaire", "Sourire et dire 'Bonjour'", "Lui donner le numéro d'attente", "L'envoyer vers l'infirmière" }, AnswerIndex = 1, Order = 1 },
                new() { Question = "Un patient se sent stressé. Que faites-vous?", Options = new() { "Lui dire de se calmer", "Reconnaître ses préoccupations et rassurer", "L'ignorer et continuer", "L'appeler au médecin immédiatement" }, AnswerIndex = 1, Order = 2 },
                new() { Question = "Pouvez-vous modifier le numéro patient après enregistrement?", Options = new() { "Oui, toujours", "Non, jamais - c'est permanent", "Oui, avec permission", "Oui, dans 24 heures" }, AnswerIndex = 1, Order = 3 },
                new() { Question = "Quel est le temps moyen d'enregistrement d'un patient?", Options = new() { "2-3 minutes", "5-10 minutes", "15-20 minutes", "30+ minutes" }, AnswerIndex = 1, Order = 4 },
                new() { Question = "Un patient a oublié son QR code. Que faites-vous?", Options = new() { "Dites qu'il doit partir et revenir", "Cherchez dans système par nom + DOB et réimprimez", "Appelez le superviseur", "Refusez le service" }, AnswerIndex = 1, Order = 5 },
                new() { Question = "Quelle est la priorité dans une file d'attente?", Options = new() { "Celui arrivé en premier", "Celui avec le plus d'argent", "Enfants, personnes âgées, urgences d'abord", "Celui qui crie le plus fort" }, AnswerIndex = 2, Order = 6 },
