    public static List<CreateTrainingModuleDto> GetMedecinModules() => new()
    {
        new()
        {
            Title = "Consultation Médicale et Diagnostic",
            Audience = "StaffMedecin",
            ShortDescription = "Excellence clinique et utilisation du système pour diagnostiquer et traiter",
            Description = "Formation complète pour médecins: consultation, diagnostic, prescription, communication avec patient et utilisation du dossier électronique",
            Level = "Avancé",
            DurationMinutes = 120,
            Tags = new() { "medecin", "formation", "consultation" },
            Steps = new()
            {
                new() { Title = "Rôle et Responsabilités Médicales", Content = "Vous êtes responsable du diagnostic et du traitement.\n\n🏥 VOTRE MISSION:\n• Évaluer cliniquement chaque patient\n• Diagnostiquer les conditions\n• Prescrire les traitements efficaces\n• Conseiller et éduquer les patients\n• Documenter précisément\n• Assurer la sécurité du patient\n• Respecter les protocoles médicaux\n\n👥 PATIENTS QUE VOUS VERREZ:\n• Premiers rendez-vous (diagnostic)\n• Suivis (consultation de contrôle)\n• Urgences (soins immédiats)\n• Référrals (autres médecins)\n\n📋 DOCUMENTATION REQUISE:\n✓ Plainte principale\n✓ Histoire médicale pertinente\n✓ Examen physique\n✓ Résultats tests/analyses\n✓ Impression clinique\n✓ Plan de traitement\n✓ Prescriptions\n✓ Instructions au patient\n\n⏰ TIMING MOYEN:\n• Nouveau patient: 20-30 min\n• Suivi: 10-15 min\n• Urgence: 10-20 min\n• Consultation: Total = 45-90 min\n\n📊 VOLUME QUOTIDIEN:\n• Typical: 15-25 patients/jour\n• Urgent: Peut varier énormément\n• Dépend équipe (infirmière, labo)\n\n💡 CONSEIL: Plus vous écoutez au début, moins vous devez poser de questions. L'écoute active = diagnostic meilleur.", Order = 1, Media = new() },
                new() { Title = "Consultation Structurée et Diagnostic", Content = "Processus de consultation efficace et systématique.\n\n🎯 LES 5 ÉTAPES DE LA CONSULTATION:\n\nÉTAPE 1: ACCUEIL (1-2 min)\n□ Levez-vous\n□ Poignée de main\n□ \"Bonjour, je suis Dr. [nom]\"\n□ Vérifiez les dossiers (nouveau vs suivi)\n□ Invitez à s'asseoir\n\nÉTAPE 2: HISTOIRE MÉDICALE (5-10 min)\nCommencez par:\n\"Comment ça va aujourd'hui?\"\nÉcoutez la réponse COMPLÈTEMENT (2-3 min)\n\nPlainte principale:\n• \"Depuis combien de temps?\"\n• \"Comment ça a commencé?\"\n• \"Aggravé par quoi?\"\n• \"Amélioré par quoi?\"\n• \"Autres symptômes?\"\n\nHistorique:\n• \"Avez-vous eu cela avant?\"\n• \"Avez-vous des allergies?\"\n• \"Prennez-vous des médicaments?\"\n• \"Conditions chroniques?\"\n• \"Antécédents chirurgicaux?\"\n• \"Antécédents familiaux pertinents?\"\n\nHistoire sociale:\n• \"Occupation?\"\n• \"Habitudes (fumeur, alcool)?\"\n• \"Situation familiale?\"\n\nÉTAPE 3: EXAMEN PHYSIQUE (5-10 min)\n\nVitaux:\n□ Temperature\n□ Pouls\n□ Tension artérielle\n□ Respiration\n□ Poids/Taille\n□ BMI\n\nExamen ciblé (selon plainte):\n\nFIÈVRE:\n• Regardez la gorge\n• Écoutez poitrine (stétho)\n• Palpez abdomen\n• Notez rougeur/inflammation\n\nTOUX:\n• Écoutez poumons antérieur/postérieur\n• Cherchez wheezing\n• Vérifiez gorge\n• Vérifiez saturation oxygène\n\nABDOMEN:\n• Palpez 4 quadrants\n• Cherchez tendresse/masses\n• Écoutez péristaltisme\n• Percutez si douleur\n\nAUTRES:\n• ENT: Otoscope, thorax ORL\n• Neuro: Réflexes, sensation\n• Cardio: Auscultation\n• Membres: Gonflement, mouvement\n\nÉTAPE 4: ANALYSE ET DIAGNOSTIC (3-5 min)\n\nDiagnostique différentiel:\n1. Diagnostic principal le plus probable\n2. Diagnostics alternatifs possibles\n3. Diagnostics dangereux à exclure\n\nTests/Analyses nécessaires:\n• Labo (sang, urine)\n• Imagerie (X-ray, échographie)\n• Spécialisé (ECG, etc.)\n\nÉTAPE 5: PLAN DE TRAITEMENT (5-10 min)\n\nDiscussion:\n• \"Voici ce que je pense...\"\n• Expliquez en termes simples\n• Répondez aux questions\n• Validez les préoccupations\n\nPrescriptions:\n• Médicaments (voir section)\n• Dosages exacts\n• Fréquence\n• Durée\n• Instructions (avec/sans repas)\n• Effets secondaires possibles\n\nAutres:\n• Repos (si needed)\n• Régime (si applicable)\n• Exercice (si appropriate)\n• Retour au travail\n• Quand revenir\n\nÉducation:\n• \"Prendre les médicaments tels que prescrits\"\n• \"Signes d'alerte = revenir immédiatement\"\n• \"Revenez si pas mieux dans X jours\"\n• \"Questions?\"\n\n🔴 SIGNES D'ALERTE (Urgence immédiate):\n• Difficultés respiratoires\n• Douleur thoracique\n• Perte de conscience\n• Saignement important\n• Trauma sévère\n• Réaction allergique\n\nSi voir = Appelez ambulance/urgences immédiatement\n\n💡 CONSEIL: Un diagnostic bien expliqué = patient adhère mieux au traitement. Prenez le temps d'expliquer correctement.", Order = 2, Media = new() },
                new() { Title = "Prescriptions et Gestion des Médicaments", Content = "Prescrire de manière sûre et efficace.\n\n💊 PRINCIPES DE PRESCRIPTION:\n\n✓ TOUJOURS vérifier:\n1. Allergie médicament (si présent?)\n2. Interactionsavec autres médicaments\n3. Contre-indications (conditions)\n4. Dosage approprié (poids, âge)\n5. Fréquence (2x jour? 3x jour?)\n6. Durée (3 jours? 2 semaines?)\n7. Instructions (avec/sans repas)\n\n📋 STRUCTURE DE PRESCRIPTION:\n\nFormat:\nDrogue | Dosage | Fréquence | Durée\nExemple: Amoxicilline 500mg | 3x par jour | 7 jours\n\nInstructions complètes:\n- \"Avec de l'eau, pendant ou après repas\"\n- \"Ne pas mâcher\"\n- \"Terminer le cours entier même si mieux\"\n- \"Effets secondaires: nausée, rash (rare)\"\n\n⚠️ ANTIBIOTIQUES:\nUtiliser seulement si vraiment nécessaire:\n✓ Infection bactérienne confirmée\n✓ Pas pour viral (rhume, grippe)\n✓ Prescrire approprié = réduire résistance\n\nDuration:\n- Infection légère: 3-5 jours\n- Infection modérée: 5-7 jours\n- Infection sévère: 10-14 jours\n- TOUJOURS finir le cours!\n\nTypes communs:\n• Amoxicilline (large spectre)\n• Ciprofloxacin (graves)\n• Trimethoprim-sulfame (urinaire)\n• Métronidazole (anaérobe)\n\n💊 ANALGÉSIQUES (Anti-douleur):\n\nPour douleur légère:\n- Paracétamol 500mg, 3-4x par jour\n- Max 4g/jour\n- Ibuprofen 200mg, 3-4x par jour\n\nPour douleur modérée:\n- Codéine 30mg + paracétamol\n- Tramadol 50-100mg, 3x par jour\n\nPour douleur sévère:\n- Morphine (si available)\n- Référez à spécialiste\n\n⚠️ DANGERS:\n• Pas plusieurs analgésiques ensemble\n• Vérifier foie (paracétamol)\n• Pas long terme sans suivi\n\n🏥 ANTI-INFLAMMATOIRES:\n- Ibuprofen 200-400mg, 3x par jour\n- Diclofenac 50mg, 2-3x par jour\n- Ne pas dépasser 7-10 jours\n- Avec repas (protéger estomac)\n\n🤒 ANTI-DIARRHÉIQUES:\n- Lopéramide 2mg après chaque selle\n- Max 6 mg/jour\n- Oral Rehydration Solution (ORS)\n- Éviter si diarrhée sanglante\n\n🍵 ANTI-NAUSÉES:\n- Métoclopramide 10mg, 3x par jour\n- Ondansetron 4mg, si grave\n- Souvent avec autres médicaments\n\n☑️ CHECK LIST AVANT PRESCRIRE:\n□ Allergie? (Patient + Dossier)\n□ Interactions? (Utiliser application)\n□ Contre-indications? (Enceinte? Foie?)\n□ Dosage correct? (Poids, âge, sévérité)\n□ Fréquence? (1x? 2x? 3x par jour?)\n□ Durée? (Appropriée pour condition)\n□ Instructions claires? (Patient comprend?)\n□ Signature? (Prescription légale)\n□ Copies au dossier? (Documentation)\n\n🔒 GESTION DES RISQUES:\n✓ Pas prescrire ce que vous ne connaissez pas bien\n✓ Vérifier avant prescrire\n✓ Documenter complètement\n✓ Patient comprend = essayer vérifier\n✓ Suivi si preoccupation\n✓ Signaler si effet négatif observé\n\n💡 CONSEIL: Bonne prescription = patient guérit. Mauvaise prescription = complications. Soyez rigoureux!", Order = 3, Media = new() },
                new() { Title = "Demande d'Analyses et Interpretation", Content = "Utiliser les tests de laboratoire et imagerie efficacement.\n\n🔬 QUAND DEMANDER DES TESTS:\n\n✓ INDICATIONS COURANTES:\n• Fièvre prolongée → Labo (complet)\n• Infection urinaire → Culture urine\n• Diarrhée → Coproculture\n• Douleur abdominale → Écho abdomen\n• Toux persistante → Chest X-ray\n• Dyspnée → Chest X-ray, oxymètre\n• Diabète → Glucose, HbA1c\n• Hypertension → Électrolytes, rein\n\n📋 TYPES DE TESTS DISPONIBLES:\n\nLABORATOIRE:\n• Complet sanguin (CBC) - Info générales\n• Électrolytes (Na, K, Cl) - Équilibre\n• Glucose - Diabète\n• Fonction rein (Creatinine, BUN)\n• Fonction foie (ALT, AST, bilirubin)\n• Lipides (Cholesterol, triglycerides)\n• TSH - Thyroïde\n• Culture/Sensibilité - Antibio approprié\n• VIH/Syphilis - Si cliniquement indiqué\n• Grossesse test (β-hCG)\n• Urinalyse\n• Stool (fèces)\n\nIMAGERIE:\n• X-Ray (thorax, abdomen, membre)\n• Échographie (abdomen, obstétrique, cardiac)\n• CT Scan (si disponible)\n• Ultrasound Doppler\n\nAUTRES:\n• ECG (électro-cardiogramme)\n• Spirométrie (fonction poumon)\n• Tension (blood pressure)\n• Oxymètre (saturation O2)\n• Température, Poids, Taille\n\n⚡ TEMPS D'ATTENTE TYPIQUE:\n• Sang: 24 heures\n• Urine: 24 heures\n• Culture: 48-72 heures\n• X-Ray: 1-2 heures\n• Échographie: 1-2 heures\n• CT: 2-4 heures (si disponible)\n\n📊 INTERPRÉTATION RÉSULTATS:\n\nVALEURS NORMALES (Ranges):\n\nGlobules blancs (WBC):\n• Normal: 4,500-11,000 μL\n• Élevé: Infection probable\n• Bas: Immunité faible\n\nHémoglobine (Hb):\n• Homme: 13.5-17.5 g/dL\n• Femme: 12.0-15.5 g/dL\n• Bas: Anémie\n\nGlucose:\n• À jeun: < 100 mg/dL\n• Après repas: < 140 mg/dL\n• Élevé: Diabète possible\n\nCréatinine:\n• Normal: 0.6-1.2 mg/dL\n• Élevé: Problème rein\n\nImagerie:\n• X-Ray: Cherchez opacité, gaz, fluide\n• Écho: Cherchez structure, fluidité, masse\n\n🔍 VALEURS ANORMALES = ACTION:\n1. Vérifier résultat (erreur de labo?)\n2. Considérer contexte clinique\n3. Traiter ou investiguer plus\n4. Informer patient\n5. Suivi approprié\n\n⚠️ RÉSULTATS CRITIQUES:\n• Glucose < 40 ou > 500 = Urgence\n• Hb < 7 = Urgence transfusion\n• K < 3 ou > 6 = Urgence cardia\n• Creatinine > 5 = Urgence rein\n• Infection sévère = Urgence antibio\n\nSI CRITIQUE:\n1. Contactez labo immédiatement\n2. Appelez patient ASAP\n3. Arrangez traitement urgent\n4. Ne pas attendre consultation de routine\n\n💡 CONSEIL: Demander test pertinent = diagnostic meilleur. Trop de tests = coût inutile. Juste bon nombre!", Order = 4, Media = new() },
                new() { Title = "Communication avec le Patient et Conseils", Content = "Expliquer le diagnostic et motiver l'adhésion au traitement.\n\n💬 COMMENT EXPLIQUER LE DIAGNOSTIC:\n\n1️⃣ UTILISEZ DES MOTS SIMPLES:\n❌ \"Vous avez une pharyngite streptococcique avec exsudat purulent\"\n✅ \"Vous avez une infection de gorge causée par une bactérie\"\n\n❌ \"Vous souffrez d'une gastro-entérite virale aiguë\"\n✅ \"Vous avez une infection intestinale qui cause la diarrhée\"\n\n2️⃣ UTILISEZ DES COMPARAISONS:\n❌ \"Le pancréas n'est pas en mesure de sécréter suffisamment d'insuline\"\n✅ \"Votre corps ne peut pas contrôler le sucre dans le sang comme il devrait\"\n\n3️⃣ VALIDEZ LES SENTIMENTS:\n• \"Je comprends que c'est stressant\"\n• \"C'est normal d'être préoccupé\"\n• \"Nous allons vous aider\"\n• \"Vous n'êtes pas seul avec ça\"\n\n4️⃣ EXPLIQUEZ LE TRAITEMENT:\n\"Voici ce que nous allons faire:\"\n1. [Traitement]\n2. [Durée]\n3. [Ce qui s'améliorera]\n4. \"Signes d'alarme = revenez\"\n\n5️⃣ VÉRIFIEZ LA COMPRÉHENSION:\n• \"Comprendre jusqu'à présent?\"\n• \"Avez-vous des questions?\"\n• \"Pouvez-vous répéter les instructions?\"\n• \"Allez-vous pouvoir prendre les médicaments comme prescrit?\"\n\n📚 ÉDUCATION DU PATIENT:\n\nPour CHAQUE condition, enseignez:\n\nCause:\n\"Comment j'ai attrapé ça?\"\n\"Ça va revenir?\"\n\nSeverité:\n\"Est-ce grave?\"\n\"Vais-je être bon?\"\n\nPrognose:\n\"Combien de temps pour guérir?\"\n\"Est-ce permanent?\"\n\nPrévention:\n\"Comment j'évite cela à l'avenir?\"\n\"Mes famille aussi?\"\n\nTraitement:\n\"Prendre comment?\"\n\"Quand?\"\n\"Avec quoi?\"\n\"Tous les jours?\"\n\n🎯 ADHÉSION AU TRAITEMENT:\n\nPourquoi les patients ne suivent pas:\n✗ Pas comprendre les instructions\n✗ Oublier de prendre les médicaments\n✗ Effets secondaires\n✗ Pas sentir de différence\n✗ Trop cher\n✗ Trop compliqué\n\nComment améliorer:\n✓ Expliquer pourquoi (compréhension)\n✓ Prescrire simple (1-2x par jour)\n✓ Courte durée si possible\n✓ Avertir des effets secondaires\n✓ \"Allez-vous pouvoir...?\"\n✓ Identifier obstacles\n✓ Proposer solutions\n✓ Suivi pour vérifier\n\n💬 PHRASES UTILES:\n\nPour rassurant:\n\"Ce n'est pas grave. Ça va guérir.\"\n\"Avec le traitement, vous vous sentirez mieux très bientôt.\"\n\"Vous êtes entre de bonnes mains.\"\n\nPour assertif:\n\"Il est très important de prendre tous les médicaments.\"\n\"Ne pas arrêter même si vous vous sentez mieux.\"\n\"Revenez immédiatement si ces symptômes apparaissent.\"\n\nPour empathique:\n\"Je sais que c'est difficile.\"\n\"Beaucoup de gens passent par là.\"\n\"Nous allons vous aider à traverser ça.\"\n\nPour direct:\n\"Vous ne comprenez pas? Expliquons autrement.\"\n\"Pouvez-vous me montrer que vous avez compris?\"\n\"Quels problèmes voyez-vous avec ce plan?\"\n\n🚫 À ÉVITER:\n✗ Jargon médical\n✗ Impatience\n✗ Jugement\n✗ Minimiser préoccupations\n✗ Donner trop info compliquée\n✗ Promettre garantie (médecine incertaine)\n✗ Parler au famille, pas au patient\n\n💡 CONSEIL: Communication bonne = patient guérit mieux. Prenez le temps d'expliquer correctement!", Order = 5, Media = new() },
                new() { Title = "Documentation et Dossier Patient Électronique", Content = "Documentation précise et complète - clé de la qualité et sécurité.\n\n📋 IMPORTANCE DE LA DOCUMENTATION:\n\n✓ Raisons:\n1. Continuité de soin (autre médecin comprend)\n2. Légal (défense si problème)\n3. Qualité (trace de ce qu'on a fait)\n4. Recherche (amélioration système)\n5. Financier (justifier les charges)\n6. Sécurité patient (pas oublier)\n\n📝 ÉLÉMENTS D'UNE BON DOSSIER:\n\nINFORMATION DE BASE:\n□ Date et heure\n□ Médecin responsable\n□ Raison de visite (chief complaint)\n□ Vital signs\n\nHISTORYE MÉDICALE:\n□ HPI (History of Present Illness)\n□ PMH (Past Medical History)\n□ Médicaments actuels\n□ Allergies\n□ Habitudes (fumer, alcool)\n□ Histoire familiale pertinente\n\nEXAMEN PHYSIQUE:\n□ Général (appearance, distress)\n□ Vitaux\n□ Examen systémique pertinent\n□ Findings anormaux noté\n\nASSESSMENT:\n□ Diagnose principale\n□ Diagnostiques alternatifs\n□ Raisonnement clinique\n\nPLAN:\n□ Tests/imagerie\n□ Prescriptions\n□ Instructionsau patient\n□ Suivi\n\n💾 DANS LE SYSTÈME INFORMATIQUE:\n\n1. Ouvrir le dossier du patient\n2. Cliquez \"Nouvelle consultation\"\n3. Remplissez:\n   - Date/Heure\n   - Plainte principale\n   - Vital signs (ou import depuis triage)\n   - Histoire\n   - Examen\n   - Assessment\n   - Plan\n   - Prescriptions\n4. Sauvegardez\n5. Signez numériquement\n\n✍️ NORMES DE DOCUMENTATION:\n\nTILLDE (Timely, Immediately, Legible, Logical, Detailed, Exact):\n✓ Timely: Même jour ou jour après\n✓ Immediately: Pas semaines plus tard\n✓ Legible: Clair et lisible (digital aide)\n✓ Logical: Cohérent et organisé\n✓ Detailed: Pas superficiel\n✓ Exact: Précis, vérifiable, complet\n\n🔐 SÉCURITÉ & CONFIDENTIALITÉ:\n✓ Jamais laisser écran débloqué\n✓ Déconnectez-vous quand partez\n✓ Donnees sensibles protégées\n✓ Jamais imprimer inutilement\n✓ Déstructire documents papier si présent\n\n⚠️ ERREURS COURANTES:\n❌ Documenter long après (mémoire vague)\n❌ Abbreviations que personne ne comprend\n❌ Copier-coller même texte (pas contextualisé)\n❌ Oublier examène physique\n❌ Plan pas assez détaillé\n❌ Prescription pas lié au diagnostic\n❌ Pas de suivi prévu\n\n✅ BON EXEMPLE:\n---\nDate: 2026-03-12 14:30\nMédecin: Dr. Traoré\n\nCHIEF COMPLAINT:\nFièvre depuis 2 jours\n\nHPI:\nPatient rapporte fièvre 38.5°C depuis 2 jours, accompagné de toux sèche et malaise général. Pas de dyspnée. Pas de douleur thoracique. Pas d'exposition connue. Antécédent: Rhume l'année dernière.\n\nVITALS:\nT: 38.7°C, P: 92, RR: 18, BP: 120/80, O2: 98%\n\nEXAMEN:\nGénéral: Patient alerte, mal à l'aise\nORL: Pharynx légèrement rouge, pas d'exsudat\nPoumons: Clairs bilatéralement\nAbdomen: Bénin\n\nASSESSMENT:\n1. Upper respiratory infection (probable)\n2. Viral vs bacterial (unclear yet)\n\nPLAN:\n1. Labo: Throat culture\n2. X-ray: Chest (si cough persist)\n3. Traitement symptomatique\n4. Suivi: 3-5 jours si pas mieux\n5. Revenez si: Dyspnée, douleur thoracique, fièvre > 39.5°C\n---\n\n💡 CONSEIL: Bonne documentation = bonne médecine. C'est la trace que vous laissez pour les autres. Soyez rigoureux!", Order = 6, Media = new() },
                new() { Title = "Urgences et Protocoles Spéciaux", Content = "Gérer les situations urgentes et suivre les protocoles de sécurité.\n\n🚨 SITUATIONS D'URGENCE COURANTES:\n\n1️⃣ DIFFICULTÉ RESPIRATOIRE:\nSignes: Dyspnée, stridor, gasping, cyanose\nAction IMMÉDIATE:\n□ Appelez ambulance/urgences\n□ Asseoir droit\n□ Oxygène si disponible\n□ Monitorer saturatino\n□ Ne pas laisser seul\n□ IV si formé\n\nCauses possibles:\n• Asthme\n• Pneumonie\n• Anaphylaxie\n• Pneumothorax\n• Pulmonary edema\n\n2️⃣ DOULEUR THORACIQUE:\nSignes: Douleur chest, dyspnée, palpitations\nAction IMMÉDIATE:\n□ Appelez ambulance/urgences\n□ ECG (si disponible)\n□ Oxygène\n□ Aspirin (si pas contre-indication)\n□ Monitoring cardiaque\n□ IV access\n\nCauses possibles:\n• MI (infarctus myocarde)\n• Angina\n• Pneumonie\n• Pulmonary embolism\n• Aortic dissection\n\n3️⃣ CONVULSIONS (Seizure):\nSignes: Perte conscience, mouvements involontaires\nAction IMMÉDIATE:\n□ Assurez sécurité (loin d'objets)\n□ Tournez sur côté\n□ Ne pas retenir\n□ Timing la durée\n□ Appelez ambulance si > 5 min\n□ Oxygène après\n□ Observation complète\n\nCauses:\n• Épilepsie\n• Fièvre (enfant)\n• Hypoglycémie\n• Toxines\n• Trauma\n\n4️⃣ CHOC (Shock):\nSignes: BP très basse, tachycardia, peau froide/humide\nAction IMMÉDIATE:\n□ Appuyez buzzer (aide)\n□ Liquides IV rapidement\n□ Oxygen\n□ Position allongé\n□ Monitorer vitals constamment\n□ Trouvez la cause\n\nCauses:\n• Hémorragie\n• Infection (septic shock)\n• Cardiaque\n• Allergique (anaphylaxis)\n\n5️⃣ ANAPHYLAXIE (Allergic reaction sévère):\nSignes: Rash, gonflement face/throat, dyspnée, hypotension\nAction IMMÉDIATE:\n□ Arrêtez le médicament/nourriture\n□ Epinephrine IM (0.3-0.5mg) ASAP\n□ IV access\n□ Oxygen\n□ Anti-histamine IV\n□ Corticosteroids\n□ Monitoring 4-6h\n□ Ambulance si grave\n\n6️⃣ HYPOGLYCÉMIE (Glucose très bas):\nSignes: Tremors, sweating, confusion, tachycardia\nAction:\n□ Mesure glucose immédiatement\n□ Si < 60: Glucose oral ou IV\n□ Donut/jus rapide (carbs)\n□ Monitoring\n□ Trouvez cause\n\n7️⃣ AVC (Stroke):\nSignes: Facedrooping, armweakness, speech slurred (FAST)\nAction IMMÉDIATE:\n□ Appelez ambulance (URGENT)\n□ Note l'heure (< 4.5h = tPA possible)\n□ Monitoring\n□ IV\n□ Ne pas donner à manger\n□ Suivi hospital\n\n⚠️ PROTOCOLES DE SÉCURITÉ:\n\nPROTOCOLE INFECTIEUX:\n✓ Masque N95 si respiratory\n✓ Gants toujours\n✓ Laver mains\n✓ Précautions de contact si bloody/excretion\n✓ Aiguille sharps dans container\n✓ Biohazard disposal pour blood/body fluids\n\nPROTOCOLE VIOLENCE:\nSi patient devient agressif:\n✓ Restez calme\n✓ Créez espace (pas bloquer exit)\n✓ Parlez lentement/bas\n✓ Appelez sécurité\n✓ Ne pas touch sans permission\n✓ Documentez\n✓ Rapportez au superviseur\n\nPROTOCOLE CONSENTEMENT:\n✓ Toujours obtenir consentement avant procédure\n✓ Expliquer risques et bénéfices\n✓ Répondre aux questions\n✓ Documenter consentement\n✓ Si confusion/incapacité → représentant légal\n\n💡 CONSEIL: Urgences requièrent courage et clarité mentale. Pratiquez ces scenarios. Connaître les protocoles = patient sauvé!", Order = 7, Media = new() }
            },
