    public static List<CreateTrainingModuleDto> GetPharmacienModules() => new()
    {
        new()
        {
            Title = "Gestion Pharmacie et Dispensation",
            Audience = "StaffPharmacien",
            ShortDescription = "Maîtriser la gestion des médicaments, stocks et dispensation sécurisée",
            Description = "Formation pour pharmaciens: gestion stocks, dispensation prescriptions, interactions médicamenteuses, sécurité et conseils patient",
            Level = "Avancé",
            DurationMinutes = 120,
            Tags = new() { "pharmacien", "formation", "medicament" },
            Steps = new()
            {
                new() { Title = "Rôle Pharmacien et Responsabilités", Content = "Vous êtes le gardien de la sécurité des médicaments.\n\n💊 VOTRE MISSION:\n• Gérer stocks de médicaments\n• Dispenser prescriptions correctement\n• Vérifier interactions médicamenteuses\n• Conseiller patients sur utilisation\n• Garantir la sécurité du traitement\n• Maintenir qualité et stabilité\n• Prévenir erreurs médicamenteuses\n• Documenter usage pharmacie\n\n⚖️ RESPONSABILITÉ LÉGALE:\nPharmacien = Dernier point de vérification avant patient\nErreur pharmacie peut être fatale\nVous êtes responsable légalement\n\n👥 PATIENTS QUE VOUS VERREZ:\n• Patients avec ordonnance\n• Questions sur médicaments\n• Conseils santé\n• Renouvellement prescriptions\n• Refus/justification (stock out, contra-indication)\n\n📋 TÂCHES QUOTIDIENNES:\n✓ Réception prescriptions\n✓ Vérification médecin signature\n✓ Check interactions\n✓ Chercher stock\n✓ Préparer médicaments\n✓ Vérifier patient (allergy check)\n✓ Conseiller patient\n✓ Documenter transaction\n✓ Gestion stock (ajuster, commander)\n\n⏰ VOLUME:\n• Typical: 30-50 ordonnances/jour\n• Urgent: Prioritaire\n• Complex: Temps extra\n\n💡 CONSEIL: Chaque prescription c'est confiance. Honorer cette confiance avec excellence!", Order = 1, Media = new() },
                new() { Title = "Dispensation de Prescription et Vérification", Content = "Processus sécurisé de dispensation.\n\n📋 RÉCEPTION ORDONNANCE:\n\nVérifications AVANT preparer:\n1. Signature médecin (lisible, valide?)\n2. Date (récente? Pas expirée?)\n3. Patient nom (lisible?)\n4. Médicament (lisible?)\n5. Dosage (approprié? Pas trop haut?)\n6. Fréquence (2x jour? 3x jour?)\n7. Durée (3 jours? 2 semaines?)\n8. Instructions (avec/sans repas?)\n\nSi quelconque doute:\nAPPELEZ LE MÉDECIN (ne pas deviner)\n\n✅ CHECKLIST VÉRIFICATION PATIENT:\n\n□ Allergie?\n  • Demandez: \"Êtes-vous allergique à?\"\n  • Vérifiez dossier\n  • Médicament prescrit = allergy?\n  → Si oui: NE PAS DISPENSER, appeler médecin\n\n□ Médicaments actuels?\n  • Demandez: \"Prenez-vous d'autres médicaments?\"\n  • Vérifiez interactions (voir section)\n  • Notez dans dossier\n\n□ Grossesse/Allaitement?\n  • \"Êtes-vous enceinte/allaitement?\"\n  • Certains médicaments CONTRE-INDIQUÉS\n  • Exemple: Antibiotiques certains, warfarin, tretinoin\n  → Si oui: Appeler médecin pour confirmation\n\n□ Conditions médicales pertinentes?\n  • Foie disease: Attention métabolisation\n  • Rein disease: Ajustement dose\n  • Diabète: Certains meds affect glucose\n  • Hypertension: Some meds interfere\n\n💊 PRÉPARATION:\n\n1. LOCALISER STOCK:\n   • Chercher dans armoire pharmacie\n   • Vérifier expiration (pas expiré?)\n   • Vérifier condition (intact? Pas endommagé?)\n   • Qty correcte disponible?\n\n2. COMPTER:\n   • Exactement le nombre prescrit\n   • Double-compter (vérifier)\n   • Pas approximation\n\n3. ÉTIQUETAGE:\n   • Nom patient\n   • Nom médicament\n   • Dosage\n   • Fréquence (2x par jour)\n   • Durée (5 jours)\n   • Expiration batch + date\n   • Avertissements (si applicable)\n   • Pharmacien signature\n\n4. EMBALLAGE:\n   • Emballage sûr (pas déchirable)\n   • Lisible\n   • Protégé light/humidité\n   • Fermé sécurisé\n\n📢 CONSEIL AU PATIENT:\n\nDites toujours:\n\"Prenez [name médicament] [dosage], [frequency], pour [duration].\nPrenez [avec/sans] repas.\nNe pas prendre si [allergie/condition].\nEffets secondaires possibles: [nausée, rash, etc.].\nSi problème, revenez ou appelez.\nQuestions?\"\n\n⚠️ SITUATIONS DIFFICILES:\n\nPatient pas satisfait du nombre de pills:\n\"C'est une semaine seulement?\"\n→ Expliquez: \"C'est ce qu'a prescrit le médecin. Vous pouvez revenir si besoin plus.\"\n\nPatient refuse de payer:\n\"C'est trop cher.\"\n→ Options: \"Avez-vous couverture? Pouvez-vous payer partiel? Veux-tu aller voir médecin pour alternative moins chère?\"\n\nPatient réaction allergique:\n\"J'ai une rash après prendre le médicament.\"\n→ STOP immediately: \"Arrêtez le médicament maintenant. Allez voir le médecin immédiatement. Apportez la bouteille. Retournez le reste.\"\n\nStock out (pas de stock):\n\"Vous n'avez pas ce médicament?\"\n→ Honnête: \"Malheureusement, ce médicament n'est pas en stock. Je peux:\n1. Commander (arrive demain/jour 3)\n2. Proposer alternative (médecin ok?)\n3. Référer autre pharmacie\nQuel préférez-vous?\"\n\n💡 CONSEIL: Dispensation correcte = traitement réussi. Ne jamais compromettre sécurité pour rapidité!", Order = 2, Media = new() },
                new() { Title = "Interactions Médicamenteuses et Contre-Indications", Content = "Vérifier que les médicaments ne se combattent pas.\n\n⚠️ INTERACTIONS GRAVES (À ÉVITER):\n\n1️⃣ ANTICOAGULANTS (Warfarin) + ASPIRIN:\n• Risque: Saignement sévère\n• Signe: Hématome, gencives saignant\n• Action: NE PAS DONNER, appeler médecin\n\n2️⃣ METFORMIN (Diabète) + Contrast Iode (Imagerie):\n• Risque: Acidose lactique (sévère)\n• Action: Arrêter metformin 48h avant imaging, puis reprendre\n\n3️⃣ ANTIBIOTIQUES + CONTRACEPTIF ORAL:\n• Risque: Contraceptif peut échouer (grossesse)\n• Signe: Patient doit utiliser contraception alternative\n• Action: Avertir patient\n\n4️⃣ LISINOPRIL (Tension) + POTASSIUM SUPPLÉMENTS:\n• Risque: Hyperkalémia (trop potassium = danger cardia)\n• Signe: Palpitations, faiblesse\n• Action: NE PAS DISPENSER, appeler médecin\n\n5️⃣ THÉOPHYLLINE + CIPROFLOXACIN:\n• Risque: Toxicité théophylline\n• Signe: Tremor, nausée, palpitations\n• Action: Monitor, réduire dose\n\n6️⃣ TRAMADOL + SSRI (Antidépresseur):\n• Risque: Serotonin syndrome\n• Signe: Agitation, tremor, fever\n• Action: Careful combination, patient education\n\n🔍 COMMENT VÉRIFIER INTERACTIONS:\n\nMETHODE 1: KNOWLEDGE (Connaître les interactions courantes)\n✓ Mémoriser interactions communes\n✓ Mise à jour avec formations\n✓ Reference book (si permis)\n\nMETHODE 2: SYSTÈME (Si available):\n✓ Computer program check\n✓ Input tous médicaments\n✓ Output: Interactions found\n✓ Vérifier chaque interaction\n\nMETHODE 3: QUESTION PATIENT:\n✓ \"Prenez-vous autre médicament?\"\n✓ \"Herbal ou suppléments?\"\n✓ \"Vitamines?\"\n✓ \"Drogues?\"\n✓ Écoutez TOUTE la liste\n\n⚠️ CONTRE-INDICATIONS COURANTES:\n\nGROSSESSE:\n✗ JAMAIS: Warfarin (fetal anomalies)\n✗ JAMAIS: ACE inhibitors (rein fetal)\n✗ JAMAIS: Tretinoin (tératogène)\n✗ JAMAIS: Streptomycin (surdité fetal)\n✗ SOYEZ ATTENTIF: Antibiotiques (demander à médecin)\n\nALLAITEMENT:\n✗ JAMAIS: Warfarin (saignement bébé)\n✗ JAMAIS: Chemotherapy\n✗ ATTENTION: Antibiotiques (vérifier)\n✗ ATTENTION: Antidépresseurs (petit risque)\n\nFOIE DISEASE:\n✗ RÉDUIRE: Paracétamol (toxicité foie)\n✗ ÉVITER: Statins (certains)\n✗ ATTENTION: Tous métabolisés par foie\n\nREIN DISEASE:\n✗ RÉDUIRE: Aminoglycosides (toxicité)\n✗ RÉDUIRE: Biguanides (acidose lactique)\n✗ ATTENTION: Néphrotoxiques drugs\n\n🔧 QUAND DOUTE:\n\n1. APPELER LE MÉDECIN:\n   \"Doctor, le patient prend [med A] et prescription est [med B].\n   Y a-t-il interaction concerns?\n   Voulez-vous alternative?\"\n\n2. DOCUMENTER:\n   • Interaction identified\n   • Médecin called (qui, quand)\n   • Décision/instruction\n   • Action taken\n\n3. INFORMER PATIENT:\n   \"Voici ce qui s'est passé.\n   Le médecin a approuvé.\n   Voici comment prendre.\"\n\n📚 RESOURCES:\n✓ Formulary (si available)\n✓ Reference books\n✓ Online tools (UpToDate, Micromedex)\n✓ Training modules\n✓ Superviseur (questions)\n\n💡 CONSEIL: Interactions = invisible mais potentiellement mortel. Vérifier = job le plus important!", Order = 3, Media = new() },
                new() { Title = "Gestion des Stocks et Commandes", Content = "Maintenir l'inventaire approprié sans surplus.\n\n📊 SYSTÈME D'INVENTAIRE:\n\nCHAQUE MÉDICAMENT A:\n✓ Quantité maximum (max stock)\n✓ Quantité minimum (reorder point)\n✓ Quantité commandée (order qty)\n✓ Localisation (où dans armoire)\n✓ Expiration tracking\n✓ Prix unitaire\n\nEXEMPLE:\nAMOXICILLINE 500mg:\n• Max: 500 tablets\n• Min (reorder): 100 tablets\n• Order Qty: 250 tablets\n• Location: Armoire A, Shelf 2\n• Expiration: Rotation FIFO (first in, first out)\n• Prix: 0.50 USD per tablet\n\n📈 TRACKING QUOTIDIEN:\n\n08h00:\n□ Vérifier stock visuellement\n□ Identifier stocks bas\n□ Notter articles à commander\n\nChaque dispensation:\n□ Reduire quantité dans système\n□ Si stock = reorder point: COMMANDER\n\n16h00:\n□ Vérifier si commandes reçues\n□ Mettre à jour système\n□ Vérifier expiration (nouvelle livraison)\n□ Stocker correctement\n\nChaque semaine:\n□ Inventory audit (spot check)\n□ Système vs physical count\n□ Discrepancy investigation\n\nChaque mois:\n□ Inventory complet\n□ Usage analysis\n□ Forecasting (besoin futur?)\n□ Waste/spoilage report\n\n🔄 ROTATION FIFO (First In, First Out):\n\n✓ Toujours dispenser medication la plus ancienne en premier\n✓ Prevent expiration waste\n✓ Meilleure qualité (pas dégradation)\n\nCOMMENT:\n1. Reçu produit → Stocker derrière old stock\n2. Dispensation → Prendre depuis front (plus vieux)\n3. Vérifier expiration avant dispenser\n\n💰 COSTING:\n\nCoût total inventaire = Capital lié\n• Trop stock = Argent attaché (opportunity loss)\n• Trop bas = Stock-out = Patient insatisfait\n• Balance = Idéal\n\nFORMULE:\nReorder Qty = (Average daily use × Lead time) + Safety stock\n\nExemple:\n• Average daily amoxicilline = 50 tablets\n• Lead time (fournisseur) = 3 jours\n• Safety stock = 50 tablets (buffer)\n• Reorder = (50 × 3) + 50 = 200 tablets\n\n📦 COMMANDE:\n\n1. Identifier besoin (stock = min point)\n2. Créer purchase order (PO):\n   • Date\n   • Fournisseur\n   • Items (nom, qty)\n   • Besoin pour date\n3. Envoyer fournisseur\n4. Suivi: Arrive quand?\n5. Réception:\n   • Vérifier QTY reçu = PO\n   • Vérifier expiration (acceptable?)\n   • Vérifier intégrité packaging\n   • Signer réception\n6. Mette à jour système\n\n⚠️ SITUATIONS:\n\nFOURNISSEUR RUPTURE:\n\"Nous n'avons pas en stock.\"\n→ Options:\n1. Alternative fournisseur?\n2. Peut-on partager avec autre pharmacy?\n3. Délai prévu?\n4. Médecin peut-il prescrire alternative?\n\nEXPIRATION APPROACH:\n\"6 mois jusqu'à expiration.\"\n→ Action:\n1. Vérifier usage rate\n2. Si pas utiliser = ordre moins\n3. Augmenter promotion (médecin)\n4. 1 mois avant = stopper vente (sauf urgence)\n\nSURSTOCK:\n\"Nous avons trop [med X].\"\n→ Action:\n1. Réduire commands\n2. Promouvoir utilisation\n3. Donation (si policy ok)\n4. Jamais laisser expire\n\n📋 DOCUMENTATION:\n\nREGISTRE INVENTAIRE:\n□ Date\n□ Médicament\n□ Quantité dispensée\n□ Quantité restant\n□ Numéro lot/batch\n□ Pharmacien\n\nREGISTRE COMMANDE:\n□ Date commande\n□ Fournisseur\n□ Items\n□ Quantité\n□ Date livraison prévue\n□ Date réception réelle\n□ Signature réception\n\n💡 CONSEIL: Bon inventory = Service bon. Trop = waste. Trop bas = frustration. Balance!", Order = 4, Media = new() },
                new() { Title = "Conseils Patient et Santé Publique", Content = "Éduquer les patients et promouvoir la santé.\n\n👥 PATIENT EDUCATION:\n\nChaque patient recevant médication doit comprendre:\n\n1️⃣ COMMENT PRENDRE:\n\"Prenez 1 comprimé, 2 fois par jour.\"\n→ Plus détail:\n• Matin (7h) et soir (19h)\n• Avec verre d'eau\n• Après petit-déjeuner (avec nourriture)\n• Avaler entier (ne pas écraser)\n\n2️⃣ DURÉE:\n\"Pour combien de jours?\"\n→ Répondre:\n• 5 jours complet\n• Terminer même si mieux\n• Pas arrêter tôt\n\n3️⃣ STOCKAGE:\n\"Où mettre le médicament?\"\n→ Directives:\n• Température ambiante (15-25°C)\n• Pas au réfrigérateur\n• Pas dans salle bain humide\n• Loin enfants/animaux\n• Armoire fermée (dark)\n\n4️⃣ EFFETS SECONDAIRES:\n\"Y a-t-il effets secondaires possibles?\"\n→ Dire les communs:\n• Nausée (léger, disparaît)\n• Rash (rare, revenez)\n• Fatigue (leger)\n→ Dire les graves (REVENIR ASAP):\n• Difficulté respiratoire\n• Gonflement visage/gorge\n• Douleur thoracique\n• Très haute fièvre\n\n5️⃣ INTERACTIONS À ÉVITER:\n\"Ne pas prendre avec [alcool/autre med].\"\n→ Expliquez pourquoi (dangereux?)\n\n6️⃣ QUESTIONS:\n\"Avez-vous des questions?\"\n→ Écoutez, répondez, validez compréhension\n\n🍎 CONSEILS SANTÉ PUBLIQUE:\n\nDEPISTAGE (Screening):\n\"Avez-vous eu dernier test [blood pressure/diabetes/HIV]?\"\n• Encourager screening\n• Donner info où aller\n• Soutenir prévention\n\nVACCINATION:\n\"Êtes-vous à jour vaccins?\"\n• Femmes enceinte → TTT (tétanos)\n• Enfants → DPT, rougeole\n• Senior → Grippe, pneumonie\n• À risque → Hepatitis B, HPV\n\nSTYLE VIE:\n\"Vous fumez? Buvez alcool?\"\n• Smoking cessation resources\n• Alcohol counseling (si needed)\n• Exercise encouragement\n• Diet advice (pour diabète, etc.)\n\nPLANIFICATION FAMILIALE:\n\"Avez-vous besoin contraception?\"\n• Options disponibles (si policy ok)\n• Education efficacité\n• Revenez si problème\n\nHYGIENE:\n\"Lavez les mains avant/après manger?\"\n• Hand washing education\n• Sanitation importante\n• Prevent spread infection\n\n🚨 SIGNES D'ALERTE À CHERCHER:\n\nPatient sembles très malades:\n→ Suggérer \"Allez voir médecin asap\"\n\nPatient dans denial (diabète, hypertension):\n→ Gentle education sur importance traitement\n\nPatient non-adhérent (oublie prendre):\n→ \"Avez-vous problème? Je peux aider?\" (pill organizer, reminder)\n\nPatient qui vole (pharynx):\n→ Report to superviseur (discrètement)\n\nPatient addicted (opioids, benzos):\n→ Offer support, ressources\n→ Médecin involvement\n\n📞 RESSOURCES PATIENT:\n\n✓ Brochures santé (si available)\n✓ Hotline (si available)\n✓ Websites (trusted)\n✓ Community programs\n✓ Counseling (mental health)\n✓ Referrals (specialist)\n\n💬 PHRASES UTILES:\n\n\"Je vais vous expliquer chaque détail.\"\n\"Pas de question bête. Je suis ici pour vous aider.\"\n\"Votre santé est importante. Prenez ces médicaments correctement.\"\n\"Si problème, revenez ou appelez. Pas d'hésitation.\"\n\"Merci d'être venu nous voir. Soyez en santé.\"\n\n💡 CONSEIL: Patient éduqué = patient adhérent = meilleur résultat. Prenez temps!", Order = 5, Media = new() },
                new() { Title = "Erreurs Courantes et Prévention", Content = "Apprendre des erreurs sans les faire.\n\n🆘 ERREUR 1: CONFUSION NOM PATIENT\nCE QUI SE PASSE: Pharamcien donne médicament patient A au patient B\nCONSÉQUENCES: Dangereux! Patient reçoit mauvais traitement\n\nCOMMENT PRÉVENIR:\n✓ Demander nom complet (pas juste prénom)\n✓ Vérifier ID patient\n✓ Dire nom à haute voix (double-check)\n✓ Attentif si beaucoup patients\n✓ Système informatique aide (photo?)\n\n🆘 ERREUR 2: MAUVAIS DOSAGE\nCE QUI SE PASSE: Prescrire 500mg mais patient reçoit 50mg (ou vice versa)\nCONSÉQUENCES: Inefficace ou overdose dangereux\n\nCOMMENT PRÉVENIR:\n✓ Lire ordonnance 2 fois\n✓ Vérifier unité (mg? mcg?)\n✓ Si dosage semble anormal → appeler médecin\n✓ Compter medication exactement\n✓ Vérifier même compte (vous + collègue)\n\n🆘 ERREUR 3: INTERACTION MISSED\nCE QUI SE PASSE: Dispenser med A avec med B qui interagissent\nCONSÉQUENCES: Patient réaction grave (hémorragie, overdose, etc.)\n\nCOMMENT PRÉVENIR:\n✓ Toujours demander autres médicaments\n✓ Vérifier système (si disponible)\n✓ Références livres (si disponible)\n✓ Doute → appeler médecin\n✓ Patient education (ne pas combiner sans permission)\n\n🆘 ERREUR 4: ALLERGIE MISSED\nCE QUI SE PASSE: Patient allergique amoxicilline reçoit amoxicilline\nCONSÉQUENCES: Anaphylaxis (peut être fatal)\n\nCOMMENT PRÉVENIR:\n✓ Toujours demander allergie directement\n✓ Vérifier dossier patient\n✓ Lire prescription (médecin note allergy?)\n✓ Reconnaître medication classes (ex: cephalosporins similar to penicillin)\n✓ Si doute allergie → confirmer avec patient (\"Penicilline c'est \"\n\n🆘 ERREUR 5: STOCK OUT SURPRENANT\nCE QUI SE PASSE: Médecin prescrit ampicilline mais \"Oh, we're out!\"\nCONSÉQUENCES: Délai traitement, patient frustré\n\nCOMMENT PRÉVENIR:\n✓ Inventory check daily\n✓ Commander avant reach minimum\n✓ Anticipate demand (époque grippe → plus antibio)\n✓ Alternative medications known\n✓ Communiquer avec médecins (stock situations)\n\n🆘 ERREUR 6: EXPIRATION MISSED\nCE QUI SE PASSE: Patient reçoit médicament 3 mois expiré\nCONSÉQUENCES: Potency réduite, possible danger\n\nCOMMENT PRÉVENIR:\n✓ Check expiration CHAQUE dispensation\n✓ FIFO rotation\n✓ Inventory purge 1x/mois (expired remove)\n✓ Vérifier batch/lot (tracking)\n\n🆘 ERREUR 7: MAUVAIS EMBALLAGE\nCE QUI SE PASSE: Comprimés sans étiquette ou étiquette lisible\nCONSÉQUENCES: Patient confusion, wrong dose\n\nCOMMENT PRÉVENIR:\n✓ Toujours étiqueter\n✓ Écriture lisible\n✓ Incluire TOUS détails (nom, dosage, fréquence, warnings)\n✓ Vérifier étiquette avant donner\n\n🆘 ERREUR 8: POOR COMMUNICATION\nCE QUI SE PASSE: Patient ne comprend pas instructions\nCONSÉQUENCES: Non-adhérence, traitement fail\n\nCOMMENT PRÉVENIR:\n✓ Parlez clairement\n✓ Demander si comprend\n✓ Montrer comment prendre (mimer?)\n✓ Écrire si besoin\n✓ Patient repeat back (vérifier)\n\n🆘 ERREUR 9: DISTRACTION HANDLING\nCE QUI SE PASSE: Collègue vous parle, you lose focus, error happens\nCONSÉQUENCES: Potential serious\n\nCOMMENT PRÉVENIR:\n✓ \"Un moment, je suis occupé avec dispensation.\"\n✓ Non-interruption zone during critical work\n✓ Check-off system (verifying each step)\n✓ Slow down when distracted\n\n🆘 ERREUR 10: THEFT/LOSS REPORTING DELAY\nCE QUI SE PASSE: Medication stolen or lost but not reported\nCONSÉQUENCES: Inventory off, patient left without, security issue\n\nCOMMENT PRÉVENIR:\n✓ Report immédiatement si missing\n✓ Honest communication (pas cacher)\n✓ Investigation rapide\n✓ Prevent future (sécurité améliorée)\n✓ Documentation (incident report)\n\n🛡️ SYSTÈME DE PRÉVENTION:\n\n1. DOUBLE-CHECK:\n   • Lecture ordonnance (pharmacien)\n   • Préparation (technician si available)\n   • Vérification (pharmacien again)\n   • Patient vérification (demander allergie)\n\n2. COMMUNICATION:\n   • Médecin → Pharmacien (si question)\n   • Pharmacien → Patient (education)\n   • Pharmacien → Superviseur (problems)\n   • Incident → Documentation\n\n3. CULTURE SAFETY:\n   • Personne doit avoir peur de parler\n   • Erreurs = learning, pas punishment\n   • Rapporter problème ASAP\n   • Équipe focused sur patient safety\n\n💡 CONSEIL: Erreur arrive. Important = rapport vite, corriger, prévenir futur. Couvrir erreur = très dangereux!", Order = 6, Media = new() },
                new() { Title = "Excellence Pharmacie et Développement Professionnel", Content = "Devenir pharmacien expert et leader.\n\n🏆 SIGNES D'EXCELLENCE:\n\n✓ Zéro erreur dispensation\n✓ Patient satisfaction élevée\n✓ Stock optimal (pas rupture, pas surplus)\n✓ Interactions détectées\n✓ Conseils patient de qualité\n✓ Rapidité et précision\n✓ Équipe cohérente\n✓ Innovation/improvement suggestions\n✓ Formation collègues\n✓ Respect profession\n\n☑️ CHECKLIST JOURNALIÈRE D'EXCELLENCE:\n\n08h00 - Arrivée:\n□ Pharmacy organized\n□ Equipment working\n□ Stock levels checked\n□ Temperature records verified\n□ Mindset prêt (focus, calm)\n\n10h00 - Mid-day:\n□ Prescription flow smooth\n□ No errors detected\n□ Patient satisfaction observed\n□ Stock adjusted (commands placed?)\n\n15h00 - Afternoon:\n□ Quality maintained\n□ Counseling thorough\n□ Documentation current\n□ Issues escalated (if any)\n\n17h00 - Fin:\n□ Pharmacy cleaned\n□ Security checked (locked?)\n□ Report written\n□ Handover to night staff (if any)\n\n☑️ COMPÉTENCES À DÉVELOPPER:\n\n1. PHARMACEUTICAL KNOWLEDGE:\n   • Drug interactions\n   • Indications/contraindications\n   • Pharmacokinetics\n   • Certification programs\n\n2. CUSTOMER SERVICE:\n   • Communication\n   • Empathy\n   • Problem-solving\n   • Feedback handling\n\n3. BUSINESS MANAGEMENT:\n   • Inventory\n   • Ordering\n   • Forecasting\n   • Cost control\n\n4. LEADERSHIP:\n   • Technician supervision\n   • Mentoring\n   • Decision-making\n   • Initiative taking\n\n5. SAFETY CULTURE:\n   • Error prevention\n   • Incident reporting\n   • Continuous improvement\n   • Training others\n\n🎯 CAREER DEVELOPMENT:\n\nMois 1-3:\n✓ Master dispensation process\n✓ Build rapport avec doctors\n✓ Learn stock system\n✓ Confidence gained\n\nMois 3-6:\n✓ Specialist certain drugs\n✓ Train technicians\n✓ Suggest improvements\n✓ Troubleshoot independently\n\nMois 6-12:\n✓ Senior pharmacist role\n✓ Lead team\n✓ Optimize operations\n✓ Mentor new staff\n✓ Consider certification/specialization\n\n🎓 CONTINUING EDUCATION:\n\n✓ Professional associations\n✓ Certification programs\n✓ Conferences/workshops\n✓ Online courses\n✓ Literature review\n✓ Collaboration with doctors\n✓ Mentorship relationships\n\n📊 PERFORMANCE METRICS:\n\nTrack your success:\n• Errors per month (target: 0)\n• Patient satisfaction (target: 95%+)\n• Inventory accuracy (target: 99%+)\n• Stock-out incidents (target: <2%)\n• Medication waste (target: <3%)\n• Staff satisfaction (target: positive)\n• Doctor feedback (target: positive)\n\n🤝 RELATIONSHIPS:\n\nWith Doctors:\n✓ Clarify prescriptions\n✓ Suggest alternatives\n✓ Share patient feedback\n✓ Gain their trust\n\nWith Patients:\n✓ Educate thoroughly\n✓ Listen concerns\n✓ Build loyalty\n✓ Support compliance\n\nWith Staff:\n✓ Train well\n✓ Support growth\n✓ Lead by example\n✓ Foster safety culture\n\nWith Supervisors:\n✓ Report accurately\n✓ Suggest improvements\n✓ Meet expectations\n✓ Take initiative\n\n💡 CONSEILS FINAUX:\n\n\"Pharmacien isn't just about giving pills.\nIt's about being guardian of medication safety.\nIt's about understanding impact on patient's life.\nIt's about being bridge between doctor and patient.\nIt's about continuous learning and excellence.\n\nYour expertise saves lives.\nYour dedication builds trust.\nYour professionalism inspires.\n\nBe excellent. Be caring. Be a true pharmacist.\"\n\n🌟 VOTRE IMPACT:\nChaque prescription correct → Traitement approprié → Patient mieux → Vie améliorée.\nYou matter.", Order = 7, Media = new() }
            },
            Quiz = new()
            {
                new() { Question = "Avant de dispenser une prescription, quelle est la PREMIÈRE vérification?", Options = new() { "Patient allergie", "Signature médecin valide et date", "Stockage disponible", "Coût" }, AnswerIndex = 1, Order = 1 },
                new() { Question = "Warfarin (anticoagulant) + Aspirin est une interaction:", Options = new() { "Mineure", "Modérée", "Grave (saignement sévère) - ÉVITER", "Aucune" }, AnswerIndex = 2, Order = 2 },
                new() { Question = "Infection à Hepatitis B → enceinte. Pouvez-vous prescrire Warfarin?", Options = new() { "Oui, c'est sûr", "Non jamais - tératogène (anomalies fetal)", "Seulement si urgence", "Oui, très faible dose" }, AnswerIndex = 1, Order = 3 },
                new() { Question = "Minimum stock reached. Que faire IMMÉDIATEMENT?", Options = new() { "Attendre jusqu'à rupture", "Commander réapprovisionnement", "Ignorer", "Vendre moins" }, AnswerIndex = 1, Order = 4 },
                new() { Question = "Patient n'est pas sûr comment prendre le médicament. Que faire?", Options = new() { "Supposer qu'il comprend", "Expliquer en détail, demander répéter", "Donner juste la bouteille", "Appeler médecin" }, AnswerIndex = 1, Order = 5 },
                new() { Question = "Quel est l'ordre correct de FIFO (First In, First Out)?", Options = new() { "Stocker nouveaux devant", "Toujours dispenser ancien en premier", "Order peu importe", "Stocker par price" }, AnswerIndex = 1, Order = 6 },
                new() { Question = "Antibiotique contaminé ou expiré trouvé. Action?", Options = new() { "Vendre moins cher", "Jeter immédiatement + report", "Utiliser quand même", "Garder en réserve" }, AnswerIndex = 1, Order = 7 },
                new() { Question = "Pharmacien's responsibilité légale est:", Options = new() { "Aucune - médecin seul responsable", "Partielle avec médecin", "Complète - dernier point de vérification avant patient", "Technician responsable" }, AnswerIndex = 2, Order = 8 }
