    public static List<CreateTrainingModuleDto> GetSuperviseurModules() => new()
    {
        new()
        {
            Title = "Leadership et Supervision d'Équipe",
            Audience = "StaffSuperviseur",
            ShortDescription = "Gérer une équipe, assurer la qualité et développer le personnel",
            Description = "Formation pour superviseurs: leadership, gestion équipe, qualité, résolution conflits, développement personnel et reportages",
            Level = "Avancé",
            DurationMinutes = 120,
            Tags = new() { "superviseur", "formation", "leadership" },
            Steps = new()
            {
                new() { Title = "Rôle et Responsabilités du Superviseur", Content = "Vous êtes le leader et gardien de la qualité.\n\n👔 VOTRE MISSION:\n• Superviser l'équipe directe\n• Assurer qualité des services\n• Développer le personnel\n• Résoudre les problèmes\n• Rapporter aux administrateurs\n• Être modèle de comportement\n• Favoriser excellence\n• Maintenir sécurité et conformité\n\n👥 ÉQUIPE SOUS VOTRE SUPERVISION:\n• Infirmiers (triage)\n• Accueil (receptionists)\n• Laborantins (lab staff)\n• Pharmaciens assistants\n• Autres (dépendant département)\n• Nombre: Typiquement 5-15 personnes\n\n📊 RESPONSABILITÉS CLÉS:\n\n1. SUPERVISION DIRECTE:\n✓ Présence à risques moments\n✓ Observation performance\n✓ Feedback immédiat\n✓ Course correction\n\n2. GESTION DE PERFORMANCE:\n✓ Évaluation régulière\n✓ Objectifs clairs\n✓ Reconnaître excellence\n✓ Adresser insuffisance\n\n3. DÉVELOPPEMENT DU PERSONNEL:\n✓ Identifier besoins formation\n✓ Offrir opportunités\n✓ Coaching\n✓ Career planning\n\n4. ASSURANCE QUALITÉ:\n✓ Standards respectés\n✓ Audit qualité\n✓ Patient satisfaction\n✓ Incident investigation\n\n5. COMMUNICATION:\n✓ Meetings d'équipe\n✓ Reporting administrateurs\n✓ Patient feedback\n✓ Transparence\n\n6. SÉCURITÉ:\n✓ Protocoles suivis\n✓ Incident reporting\n✓ Corrective actions\n✓ Continuous improvement\n\n⏰ RESPONSABILITÉ MANAGÉRIALE:\n• Budget (si applicable)\n• Horaires\n• Ressources\n• Planning\n• Hiring/Firing\n\n💡 CONSEIL: Leadership par exemple, pas par peur. Respectable, pas dictateur!", Order = 1, Media = new() },
                new() { Title = "Management d'Équipe et Motivation", Content = "Créer une équipe performante et motivée.\n\n👥 TYPES DE MEMBRES D'ÉQUIPE:\n\n1. SUPER-PERFORMERS:\n✓ Excellence naturel\n✓ Initiative\n✓ Mentor potentiel\n→ ACTION: Reconnaître, promouvoir, offrir responsabilités plus\n\n2. SOLID PERFORMERS:\n✓ Fiable\n✓ Suit instructions\n✓ Bon attitude\n→ ACTION: Support, development opportunities, reconnaissance\n\n3. LEARNERS/NEWBIES:\n✓ Potentiel mais inexpérience\n✓ Questions normales\n✓ En développement\n→ ACTION: Mentoring, patience, feedback constructive\n\n4. STRUGGLERS:\n✓ Performance insuffisant\n✓ Personal issues\n✓ Besoin support\n→ ACTION: Coaching, identify issues, plan improvement, follow-up\n\n5. PROBLEMATIC:\n✓ Résistant changement\n✓ Attitude négative\n✓ Non-collaborative\n→ ACTION: Direct conversation, clarity expectations, possible discipline si persistent\n\n🎯 MOTIVATION & ENGAGEMENT:\n\nCHOSES QUE MOTIVENT GENS:\n✓ Reconnaissance (\"You did great!\")\n✓ Opportunity (advancement)\n✓ Purpose (\"You make difference\")\n✓ Development (learning)\n✓ Fair treatment\n✓ Voice (they're heard)\n✓ Camaraderie (team spirit)\n✓ Leadership visible\n\nCHOSES QUE DÉMOTIVENT:\n✗ Pas de recognition\n✗ Favoritism\n✗ Impossible expectations\n✗ Poor leadership\n✗ No growth\n✗ Feeling invisible\n✗ Conflict unaddressed\n✗ Inconsistency\n\n💬 COMMUNICATION EFFICACE:\n\nFREQUENCY:\n• Daily: Quick check-ins\n• Weekly: Team meeting\n• Monthly: One-on-ones\n• Quarterly: Formal review\n\n1️⃣ FEEDBACK POSITIF:\nQUAND: Immédiatement après good performance\nCOMMENT: Specific, sincere, public (si possible)\nEXEMPLE:\n\"Sarah, vous avez résolu cette plainte patient magnifiquement. Vous avez écouté, compris, et trouvé solution. C'est exactement le type de excellence qu'on cherche. Bien joué!\"\n\n2️⃣ FEEDBACK CORRECTIF:\nQUAND: Immédiatement, privée\nCOMMENT: Descriptive (pas personnel), constructive, supportive\nEXEMPLE:\n\"Jean, ce matin vous avez semblé impatient avec patient. Je sais vous êtes occupé, mais patient est stressé aussi. Comment peut-on aider? Besoin de break? Support?\"\n\n3️⃣ COACHING:\nPROCESS:\n1. Observe performance\n2. Ask questions (understand)\n3. Suggest approach\n4. Practice together\n5. Feedback\n6. Follow-up\n\n⚠️ RÉSOLUTION DE CONFLIT:\n\nSITUATION: Two team members conflict\nAPPROACH:\n1. Parle à chacun individuellement\n2. Écoute leur perspective\n3. Gather facts\n4. Meet ensemble (faciliter)\n5. Find common ground\n6. Agree on forward\n7. Follow-up\n\n☑️ ÉQUIPE MEETING:\n\nFREQUENCY: Weekly (1 hour)\nATTENDANCE: Toute l'équipe\nAGENDA:\n• Previous action items (done?)\n• Quality metrics (patient complaints?)\n• Announcements\n• Training/development\n• Q&A\n• Appreciation (acknowledge)\n\nTONE:\n✓ Professional\n✓ Collaborative\n✓ Transparent\n✓ Supportive\n✓ Solutions-focused\n\n🎓 DÉVELOPPEMENT DU PERSONNEL:\n\n1. Identify strengths:\n   \"En quoi êtes-vous bien?\"\n   \"Quel area vous aime?\"\n\n2. Identify growth areas:\n   \"Où voulez-vous développer?\"\n   \"Quels skills manquent?\"\n\n3. Create plan:\n   • Specific goals\n   • Timeline\n   • Resources\n   • Support\n\n4. Support:\n   • Training\n   • Mentoring\n   • Opportunities\n   • Feedback\n\n5. Evaluate:\n   • Progress\n   • Adjust plan\n   • Celebrate success\n\n💡 CONSEIL: Leader investi = équipe motivée = excellence résultat. Investir dans gens!", Order = 2, Media = new() },
                new() { Title = "Assurance Qualité et Gestion d'Incidents", Content = "Maintenir standards élevés et apprendre des problèmes.\n\n📊 QUALITÉ = PATIENTS HEUREUX:\n\nDIMENSIONS DE QUALITÉ:\n• Efficacité (treatment works)\n• Sécurité (no harm)\n• Respect (patient dignity)\n• Timeliness (pas long wait)\n• Équité (everyone treated fairly)\n• Coordination (services integrated)\n\n🔍 ASSURANCE QUALITÉ - PROCESS:\n\n1️⃣ ÉTABLIR STANDARDS:\nExemple - Accueil:\n✓ Greeted within 2 minutes\n✓ Smile and professional tone\n✓ Accurate registration\n✓ Payment collected\n✓ Patient knows next step\n\nExemple - Labo:\n✓ Results accurate\n✓ No hemolysis\n✓ Correct identification\n✓ Results reported < 24h\n✓ Critical values flagged\n\n2️⃣ MONITORING:\n✓ Daily observations\n✓ Patient satisfaction surveys\n✓ Incident reports\n✓ Audit spot-checks\n✓ Metrics tracking\n\n3️⃣ DATA ANALYSIS:\n✓ Trends identified\n✓ Root causes\n✓ Improvement areas\n✓ Success stories\n\n4️⃣ ACTION PLANNING:\n✓ Changes identified\n✓ Resources allocated\n✓ Staff trained\n✓ Timeline set\n\n5️⃣ EVALUATION:\n✓ Monitoring improvements\n✓ Success measurement\n✓ Adjustments if needed\n✓ Sustainability\n\n📋 PATIENT SATISFACTION:\n\nMeasure regularly:\n• Surveys (paper/digital)\n• Complaints (track)\n• Compliments (recognize)\n• Focus groups\n• One-on-one feedback\n\nACTION ON FEEDBACK:\n• Positive: Share with team\n• Negative: Investigate\n• Trends: Address systematically\n• Public: Thank and act\n\n🚨 INCIDENT MANAGEMENT:\n\nINCIDENT = Anything not as intended\n• Medical error\n• Near-miss\n• Patient complaint\n• Equipment failure\n• Safety concern\n• Communication break\n\n⚡ WHEN INCIDENT OCCURS:\n\nIMMEDIATE (if emergency):\n1. Ensure patient safe\n2. Get medical help if needed\n3. Document what happened\n4. Preserve evidence\n5. Notify supervisor\n\nACUTE (within hours):\n1. Gather information\n2. Interview involved staff\n3. Check policies/procedures\n4. Determine severity\n5. Notify administrator if serious\n6. Communicate to patient (if appropriate)\n\nINVESTIGATION (within days):\n1. ROOT CAUSE ANALYSIS:\n   • What happened? (facts)\n   • When? (timeline)\n   • Why? (root cause - not just symptom)\n   • Who was involved?\n   • What were contributing factors?\n   • Could it happen again?\n\n2. DOCUMENT:\n   • Written report\n   • Interviews documented\n   • Evidence collected\n   • Facts separated from interpretation\n   • Recommendations clear\n\n3. EXAMPLE ROOT CAUSE:\n   ❌ Wrong: \"Nurse forgot to label specimen\"\n   ✅ Right: \"Nurse distracted by multiple phone calls + no system reminder. No double-check process before lab processing.\"\n\n4. CORRECTIVE ACTION:\n   • Immediate (fix the problem)\n   • Short-term (prevent recurrence)\n   • Long-term (systematic improvement)\n   • Example:\n     Immediate: Relabel specimen, redo analysis\n     Short-term: Refresher training on labeling\n     Long-term: Implement computer reminder + physical label check\n\n5. FOLLOW-UP:\n   • Action completed?\n   • Effective?\n   • Any new issues?\n   • Document resolution\n   • Share learning with team\n\n🎓 LEARNING FROM INCIDENTS:\n\nCULTURE NON-PUNITIVE:\n\"L'incident est opportunité d'apprendre, pas de punir.\"\n✓ Staff report honestly\n✓ Trust superviseur\n✓ System improved\n✓ Patient safety enhanced\n\nVS.\n\nCULTURE PUNITIVE:\n\"Staff cache incident, déniant responsabilité.\"\n✗ Système non-améliore\n✗ Même erreur répétée\n✗ Patient safety risque\n✗ Mauvais moral\n\n📣 COMMUNICATION:\n\nTo staff:\n\"Error happened. Here's what. Here's why. Here's what we're doing. Here's how we prevent. Questions?\"\n\nTo patient (if applicable):\n\"An error occurred. We apologize. Here's what happened. Here's how we fixed it. Here's what we're doing to prevent.\"\n\nTo management:\n\"Incident report: [details]. Root cause: [analysis]. Action taken: [corrective]. Prevention: [system change].\"\n\n💡 CONSEIL: Culture non-punitive = meilleur system. Punir = covering up = danger!", Order = 3, Media = new() },
                new() { Title = "Gestion Administrative et Reporting", Content = "Gérer données, rapports et administration.\n\n📊 DONNÉES & METRIQUES:\n\nCOLLECTER RÉGULIÈREMENT:\n\n📈 PERFORMANCE INDICATORS:\n• Patient volume (daily, weekly, monthly)\n• Patient satisfaction (surveys, complaints)\n• Staff performance (quality, attendance)\n• Financials (revenue, costs)\n• Incidents (near-misses, errors)\n• Training completion\n• Equipment uptime\n• Inventory accuracy\n\n🎯 TRACKING:\n• Spreadsheet (basic)\n• Database (medium)\n• Software (advanced)\n• Visualizations (charts)\n• Trends (analysis)\n\n📋 DAILY REPORT:\n\nTYPICALLY INCLUDES:\n□ Patient count\n□ Incidents/issues\n□ Staff attendance\n□ Equipment problems\n□ Complaints\n□ Successes\n□ Plans for next day\n\nFORMAT:\n\"2026-03-12 DAILY REPORT:\nPatients seen: 23\nIncidents: 0\nStaff: All present\nEquipment: All working\nComplaints: 1 (resolved)\nSuccess: Patient feedback positive\nTomorrow: Normal operations planned\"\n\n📅 WEEKLY REPORT:\n\nCOLLECT:\n□ Total patient volume\n□ Satisfaction average\n□ Staff performance review\n□ Financial summary\n□ Quality metrics\n□ Issues arising\n□ Training delivered\n□ Equipment maintenance\n\nANALYZE:\n✓ Trends\n✓ Comparisons (previous week)\n✓ Targets met?\n✓ Concerns?\n\n📆 MONTHLY REPORT:\n\nCOMPREHENSIVE:\n□ Complete month statistics\n□ Performance vs. targets\n□ Quality metrics\n□ Financial (revenue, expenses)\n□ Incidents analysis\n□ Staff development\n□ Training completed\n□ Equipment status\n□ Achievements\n□ Challenges\n□ Recommendations\n\nFORMAT:\n1. Executive summary (1-2 pages)\n2. Detailed data (tables, charts)\n3. Analysis (trends, comparisons)\n4. Issues (problems, solutions)\n5. Recommendations (next month)\n\n💰 FINANCIAL REPORTING:\n\nTRACK:\n✓ Revenue (by department, service)\n✓ Costs (staff, supplies, equipment)\n✓ Profit margin\n✓ Budget vs. actual\n✓ Variances (why different?)\n\nEXAMPLE:\nBudget (monthly):   $50,000\nActual spent:       $51,500\nVariance:           +$1,500 (5% over)\n\nWhy? \n• Staff overtime: +$800 (unexpected absence)\n• Supplies: +$700 (emergency purchase)\n\nAction:\n• Review scheduling\n• Negotiate better supply prices\n\n📧 COMMUNICATION:\n\nFREQUENCY:\n✓ Daily: Shift handover\n✓ Weekly: Staff meeting + report to admin\n✓ Monthly: Formal report + meeting\n✓ Quarterly: Extended review\n\nQUALITY:\n✓ Accurate (check data twice)\n✓ Timely (on time)\n✓ Clear (understood easily)\n✓ Concise (not verbose)\n✓ Actionable (recommendations clear)\n✓ Honest (don't hide problems)\n\n📱 DOCUMENTATION:\n\nKEEP:\n✓ Incident reports (copies)\n✓ Staff evaluations\n✓ Training records\n✓ Metrics spreadsheet\n✓ Meeting minutes\n✓ Correspondence\n✓ Policies/procedures\n✓ Equipment maintenance log\n✓ Supplier information\n✓ Patient feedback\n\nSTORAGE:\n✓ Secure (confidential)\n✓ Organized (easy to find)\n✓ Backed up (not lost)\n✓ Retention (follow policy)\n✓ Accessible (authorized only)\n\n🔒 CONFIDENTIALITY:\n\n✓ Patient information: Private\n✓ Staff evaluation: Confidential\n✓ Financial: Secure\n✓ Incident reports: Limited access\n✓ Never gossip\n✓ Share on need-to-know basis\n\n⚠️ RED FLAGS:\n\nIf you see:\n• Unusual patterns (incident spike)\n• Financial variances (large +/-)\n• Staff issues (absences, conflicts)\n• Patient complaints (trend)\n• Equipment failures (repeated)\n• Quality decline (metrics down)\n\nACTION:\n1. Investigate quickly\n2. Identify root cause\n3. Develop solution\n4. Implement\n5. Monitor improvement\n\n💡 CONSEIL: Données accurate = decisions bon. Rapports honest = trust gagnée!", Order = 4, Media = new() },
                new() { Title = "Conflit et Résolution de Problèmes", Content = "Naviguer difficultés et résoudre conflicts.\n\n⚡ TYPES DE CONFLIT:\n\n1️⃣ INTERPERSONAL (staff vs staff):\nCause: Personnalité, miscommunication, competition\nExample: Infirmier pense laborantin sloppy\n\n2️⃣ PERFORMANCE (staff vs standards):\nCause: Inability, motivation, resources\nExample: Accueil trop slow, file s'allonge\n\n3️⃣ ROLE (unclear expectations):\nCause: Ambiguous job, overlap\nExample: Infirmier vs accueil - qui fait triage?\n\n4️⃣ RESOURCE (not enough):\nCause: Budget, time, equipment\nExample: \"We're understaffed!\"\n\n5️⃣ PATIENT (dissatisfaction):\nCause: Service, outcome, price\nExample: Longue wait time → plainte\n\n🎯 RESOLUTION PROCESS:\n\nSTEP 1: GATHER INFORMATION\n\nTalk to involved parties SEPARATELY:\n✓ \"Tell me what happened.\"\n✓ Listen completely\n✓ Ask clarifying questions\n✓ Take notes\n✓ Don't interrupt\n✓ Validate feelings (\"I understand\")\n✓ Don't judge yet\n\nEXAMPLE:\nANNA: \"Jean toujours interrompt quand je parle!\"\nSUP: \"Tell me more.\"\nANNA: \"Ce matin, j'expliquais à patient, il dit \"you're doing it wrong.\" J'étais embarrassée. Pas premiere fois!\"\nSUP: \"Comment ça te fais sentir?\"\nANNA: \"Frustrated. Disrespected. I'm good at my job!\"\n\nJEAN: \"Anna too slow. Patients waiting. I'm trying to help.\"\nSUP: \"But how did you say it?\"\nJEAN: \"I maybe not best tone. I'm just frustrated.\"\n\nSTEP 2: IDENTIFY ROOT CAUSE\n\nDig deeper:\n✓ Why is Anna slow?\n   → Understaffed? Inexperience? Equipment issue?\n✓ Why is Jean frustrated?\n   → Pressure? Personal issue? Bad attitude?\n✓ What's the real issue?\n   → Not just \"Anna slow\" but \"System inefficient\"\n\nSTEP 3: FIND COMMON GROUND\n\nMeet beide ensemble (if safe):\n\"Both care about patient care.\nBoth want efficient process.\nBoth deserve respect.\"\n\nSTEP 4: DEVELOP SOLUTION\n\nOptions:\n1. Process improvement (not about blame)\n2. Training (if skill gap)\n3. Equipment (if resource issue)\n4. Communication protocol (if conflict)\n5. Schedule adjustment (if workload)\n\nEXAMPLE:\n\"Let's improve workflow:\n- Anna: Use checklist (faster)\n- Jean: Ask how help instead of criticize\n- Both: Respect each other's methods\n- Supervisor: Check daily progress\"\n\nSTEP 5: FOLLOW-UP\n\n✓ Monitor improvement\n✓ Recognize positive change\n✓ Adjust if needed\n✓ Document (formal or informal)\n✓ Prevent re-escalation\n\n⚠️ DIFFICULT CONVERSATIONS:\n\nWHEN: Staff not meeting standards\nHOW:\n\n1. PREPARE:\n✓ Facts documented\n✓ Specific examples\n✓ Privacy arranged\n✓ Calm mindset\n\n2. APPROACH:\n\"I want to discuss your performance.\"\n✓ Descriptive (not judging)\n✓ Specific (not general)\n✓ Heard (they explain)\n✓ Supportive (help, not punish)\n\nEXAMPLE:\n\"Pierre, I noticed last week you were absent 3 times without notice. This creates schedule gaps. Talk me through what's happening.\"\n\n3. LISTEN:\n✓ He explains situation\n✓ You understand context\n✓ Maybe personal issue\n\n4. DEVELOP PLAN:\n\"Here's what needs to happen:\n- Notify 24h ahead (emergencies exception)\n- Document absence\n- If pattern, we'll talk formally\n- How can I support?\"\n\n5. DOCUMENT:\n\"Just to confirm, we agreed...\"\n\"If this continues, next step is [formal discipline].\"\n\n🆘 ESCALATION:\n\nWHEN to escalate to administrator:\n• Safety concern (immediate)\n• Repeated violation (after coaching)\n• Staff insubordination\n• Harassment/discrimination\n• Legal issue\n• Major incident\n\nHOW:\n\"I've attempted to resolve. It's not improving. I'm escalating per protocol.\"\n\n💼 CONFLICT AVOIDANCE:\n\nPREVENTION:\n✓ Clear expectations (written)\n✓ Regular communication\n✓ Feedback culture (safe)\n✓ Transparency (why decisions)\n✓ Fair treatment (consistency)\n✓ Team building (camaraderie)\n✓ Appreciation (recognition)\n\n💡 CONSEIL: Most conflicts = communication fail. Communicate clair et often = problems prevented!", Order = 5, Media = new() },
                new() { Title = "Excellence Leadership et Développement Continu", Content = "Devenir excellent superviseur et leader inspirant.\n\n🏆 SIGNES D'EXCELLENCE:\n\n✓ Équipe performante et motivée\n✓ Qualité constamment haute\n✓ Patient satisfaction excellent\n✓ Low turnover (staff loyale)\n✓ Zero safety incidents\n✓ Innovation et improvements\n✓ Staff development visible\n✓ Leadership respecté\n✓ Results exceeding targets\n✓ Positive culture\n\n☑️ CHECKLIST SUPERVISEUR EXCELLENCE:\n\nDAILY:\n□ Present during operations\n□ Observe quality\n□ Quick feedback (positive)\n□ Address issues immediately\n□ Support staff\n□ Listen to concerns\n□ Walk around (visible leadership)\n\nWEEKLY:\n□ Team meeting (structured)\n□ One-on-ones (check-ins)\n□ Metrics review (on track?)\n□ Quality audit (spot check)\n□ Report written\n□ Feedback to admin\n\nMONTHLY:\n□ Formal evaluations\n□ Training needs assessed\n□ Goals reviewed\n□ Incident analysis\n□ Comprehensive report\n□ Recognition event (celebrate wins)\n□ Professional development\n\n🎯 LEADERSHIP QUALITIES:\n\n1. INTEGRITY:\n✓ Keep promises\n✓ Be honest\n✓ Lead by example\n✓ Fair and consistent\n\n2. COMMUNICATION:\n✓ Listen actively\n✓ Clear directions\n✓ Open feedback\n✓ Transparent decisions\n\n3. VISION:\n✓ Understand bigger picture\n✓ Inspire toward goals\n✓ Continuous improvement\n✓ Innovation thinking\n\n4. EMPATHY:\n✓ Understand feelings\n✓ Support struggles\n✓ Recognize stress\n✓ Show care\n\n5. DECISION-MAKING:\n✓ Timely\n✓ Informed\n✓ Consultative\n✓ Decisive (not wishy-washy)\n\n6. ACCOUNTABILITY:\n✓ Own mistakes\n✓ Take responsibility\n✓ Follow through\n✓ Results-oriented\n\n📊 PERFORMANCE METRICS (YOUR Leadership):\n\nTrack your success:\n• Staff satisfaction (survey)\n• Turnover rate (low = good)\n• Incident rate (low = good)\n• Quality metrics (high = good)\n• Patient satisfaction (high = good)\n• Budget compliance (on target)\n• Staff development (certifications achieved)\n• Team metrics vs. facility average\n\n🎓 CONTINUOUS LEARNING:\n\n✓ Leadership training (external)\n✓ Read leadership books\n✓ Attend conferences\n✓ Mentor with other supervisors\n✓ Reflection (what works?)\n✓ Feedback from team (360 review)\n✓ Certification programs\n✓ Self-awareness (strengths/weaknesses)\n\n🤝 YOUR LEADERSHIP IMPACT:\n\nRemember:\nYour team reflects you.\n✓ You're positive → team positive\n✓ You're fair → team respects you\n✓ You're invested → team engaged\n✓ You're clear → team confident\n✓ You're supportive → team loyal\n✓ You're excellent → team excellent\n\n💡 CONSEIL FINAL:\n\"Leadership n'est pas position, c'est influence.\nVous influencez chaque jour.\nInfluence vers excellence = équipe excellence.\n\nVous n'êtes pas juste supervisor.\nVous êtes mentor, guide, role model.\nYour legacy = team you developed.\n\nBe the leader you'd want to work for.\"\n\n🌟 YOUR IMPACT:\nGreat supervisor → Great team → Great results → Patients better → Organization thrives.\nYou matter deeply.", Order = 6, Media = new() }
            },
            Quiz = new()
            {
                new() { Question = "Quelle est la première action quand un incident sérieux se produit?", Options = new() { "Blâmer quelqu'un", "Assurer sécurité du patient et documenter", "Attendre et voir", "Informer admin seulement" }, AnswerIndex = 1, Order = 1 },
                new() { Question = "Culture non-punitive pour incidents signifie?", Options = new() { "Pas de consequences", "Apprendre, pas punir - staff rapport honnêtement", "Ignorer les erreurs", "Punition sévère" }, AnswerIndex = 1, Order = 2 },
                new() { Question = "Conflict entre deux staff members. Première action?", Options = new() { "Ignorer", "Parler à chacun séparément, écouter", "Punir celui qui a raison moins", "Réunion publique" }, AnswerIndex = 1, Order = 3 },
                new() { Question = "Feedback positif doit être donné?", Options = new() { "Rarement", "En privé seulement", "Immédiatement et spécifique", "Une fois par an" }, AnswerIndex = 2, Order = 4 },
                new() { Question = "Root cause analysis vrai but c'est?", Options = new() { "Trouver qui blâmer", "Trouver POURQUOI c'est arrivé, pas juste quoi", "Rapporter au patron", "Punir l'erreur" }, AnswerIndex = 1, Order = 5 },
                new() { Question = "Meeting d'équipe hebdomadaire doit inclure?", Options = new() { "Juste problèmes", "Metrics, announcements, Q&A, appreciation", "Juste instructions", "Pas utile" }, AnswerIndex = 1, Order = 6 },
