        new()
        {
            Title = "Utiliser Brigade Médicale - Guide Patient",
            Audience = "Patient",
            ShortDescription = "Comprendre comment utiliser notre application et services",
            Description = "Guide complet pour patients: créer compte, trouver services, réserver consultations, accéder dossier et bons conseils santé",
