            Steps = new()
            {
                new() { Title = "Bienvenue à Brigade Médicale", Content = "Bienvenue dans notre centre médical!\n\n🏥 NOTRE MISSION:\nProvi des soins de santé de qualité, accessible et respectueux à tous.\n\n✨ CE QUI NOUS REND DIFFÉRENT:\n• Staff professionnels et bienveillants\n• Équipement moderne\n• Service rapide\n• Prix transparent\n• Sécurité données patient\n• Continuité de soins\n\n📱 COMMENT COMMENCER:\n\n✅ OPTION 1: En ligne (si vous avez internet)\n1. Aller à site web: www.brigademedicale.ci\n2. Cliquer \"Patient Onboarding\"\n3. Remplir formulaire\n4. Recevoir numéro patient unique\n5. Télécharger QR code personnel\n\n✅ OPTION 2: Au centre (si pas internet)\n1. Venir au centre directement\n2. Personnel accueil vous aide\n3. Remplir formulaire papier\n4. Reçoit numéro patient\n5. Reçoit QR code\n\n💳 NUMÉRO PATIENT:\n• Format: BM-YYYY-XXXXX (exemple: BM-2026-00001)\n• PERMANENT - ne change jamais\n• Conservez précieusement\n• Utilisé pour chaque visite\n\n📲 QR CODE:\n• Code barre personnel\n• Permet accès rapide dossier\n• Imprimez ou sauvegardez sur téléphone\n• Montrez à réception chaque visite\n\n⏰ HORAIRES:\n• Lundi-Vendredi: 08h00-17h00\n• Samedi: 08h00-12h00\n• Dimanche: FERMÉ\n• Urgence: 24h/24\n\n📍 LOCALISATION:\nAdresse: [Sera fournie par centre]\nTéléphone: [Sera fourni]\nEmail: info@brigademedicale.ci\n\n🚗 ACCÈS:\n• Parking disponible\n• Transport en commun près\n• Accessible handicapé\n• Accès facile\n\n💡 CONSEIL: Arrivez 10 minutes avant pour enregistrement!", Order = 1, Media = new() },
                new() { Title = "Préparer Votre Visite", Content = "Bien préparer = Visite meilleure.\n\n📋 AVANT DE VENIR:\n\n1️⃣ DOCUMENTS À APPORTER:\n□ Numéro patient (BM-XXXX-XXXXX)\n□ Pièce d'identité (carte nationale, passeport)\n□ Carte assurance (si vous en avez)\n□ Référence (si envoyé par autre médecin)\n□ Médicaments actuels (pour montrer)\n□ Notes santé (si vous suivez quelque chose)\n\n2️⃣ INFORMATIONS À MÉMORISER:\n✓ Votre groupe sanguin\n✓ Vos allergies (très important!)\n✓ Maladies passées\n✓ Opérations précédentes\n✓ Médicaments actuels\n✓ Numéro contact urgence\n\n3️⃣ PRÉPARATION PHYSIQUE:\n□ Manger léger (pas affamé)\n□ Apporter eau (attente possible)\n□ Vêtements confortables\n□ Arriver à l'heure\n□ Si triage: à jeun parfois (demander)\n\n4️⃣ QUESTIONS À PRÉPARER:\nAyez liste de questions:\n• Symptômes (depuis quand?)\n• Préoccupations (spécifique?)\n• Objectifs (pourquoi visite?)\n• Antécédents (important?)\n\n5️⃣ HISTORIQUE À COMMUNIQUER:\nSoyez prêt parler de:\n• Plainte principale (pourquoi venir?)\n• Symptômes (où? combien temps?)\n• Cause possible (vous pensez?)\n• Précédents similaires\n• Traitements passés\n• Résultats (ça a aidé?)\n\n⏰ TIMING:\n• Arriver 10-15 min avant\n• Enregistrement 5-10 min\n• Attente variable (dépend)\n• Visite 10-30 min (selon type)\n• Paiement 2-3 min\n• Total: 45-90 min par visite\n\n💰 COÛTS:\nConsultation: ~15,000 FCFA\nAnalyses: Variable (10,000-50,000)\nMédicaments: Selon prescription\n\n✓ Pas de surprise - prix transparent\n✓ Payment plans disponible (si needed)\n✓ Facture fournie\n\n🚫 À ÉVITER:\n✗ Arriver sans documents\n✗ Être en retard (peut être reclassé)\n✗ Être alcoolisé\n✗ Attitude agressive\n✗ Oublier allergies\n✗ Mentir sur symptômes\n\n💡 CONSEIL: Meilleure préparation = meilleur soins. Prenez le temps!", Order = 2, Media = new() },
                new() { Title = "Votre Dossier Patient et Confidentialité", Content = "Vos données sont protégées et accessibles.\n\n📁 VOTRE DOSSIER ÉLECTRONIQUE:\n\n✓ QU'IL CONTIENT:\n• Informations de base (nom, date naissance)\n• Historique médical (maladies, opérations)\n• Consultations (notes médecin)\n• Analyses (résultats labo)\n• Prescriptions (médicaments)\n• Allergies (très important)\n• Vaccinations\n• Notes du personnel\n\n✓ QUI PEUT ACCÉDER:\n• Vous (patient)\n• Médecin qui vous soigne\n• Personnel infirmier (triage)\n• Pharmacien (si prescription)\n• Administrateurs (gestion)\n• JAMAIS staff sauf raison professionnelle\n\n🔒 SÉCURITÉ & CONFIDENTIALITÉ:\n\n✓ VOtre dossier est:\n• Sécurisé (mot de passe protégé)\n• Privé (pas public)\n• Confidentiel (limité accès)\n• Légalement protégé (loi vie privée)\n• Sauvegardé (pas perdu)\n\n✗ NON PARTAGÉ AVEC:\n• Employeur (sans permission)\n• Assurance (sans permission)\n• Famille (sans permission)\n• Autres patients (jamais!)\n• Public (jamais!)\n\n📱 ACCÉDER VOTRE DOSSIER:\n\n✓ SI VOUS AVEZ INTERNET:\n1. Allez site: www.brigademedicale.ci\n2. Login: Votre numéro patient + mot de passe\n3. Cliquez \"Mon Dossier\"\n4. Voir consultations, analyses, prescriptions\n5. Télécharger copies si needed\n\n✓ SI PAS INTERNET:\n1. Venir au centre\n2. Demander à réception\n3. Personnel vous montre dossier\n4. Imprime copies (petit frais)\n\n🔑 MOT DE PASSE:\n\n✓ IMPORTANT:\n• Ne jamais partager\n• Changez régulièrement\n• Complexe (letters + nombres + symboles)\n• Mémorisez (écrivez nulle part)\n\nSi oublié:\n1. Click \"Mot de passe oublié\"\n2. Email reçu avec reset link\n3. Créer nouveau\n4. Accès retrouvé\n\n❓ QUESTIONS SUR VOS DONNÉES:\n\nDroits légaux:\n✓ Accéder votre dossier\n✓ Recevoir copies\n✓ Corriger erreurs\n✓ Demander suppression (limites)\n✓ Savoir qui accède\n\nSi problème confidentialité:\n1. Parler au superviseur\n2. Faire plainte formelle\n3. Escalade si non-résolu\n\n⚠️ SIGNALER LES PROBLÈMES:\n\nSi vous voyez:\n• Erreur dans dossier\n• Accès non-autorisé\n• Fuites données\n• Confidentialité violée\n\nFaites:\n1. Contactez immédiatement\n2. Documenter le problème\n3. Demander correction\n4. Escalade si grave\n\n💡 CONSEIL: Vos données = votre droit. Nous protégeons précieusement!", Order = 3, Media = new() },
                new() { Title = "Comprendre les Traitements et Médicaments", Content = "Utiliser correctement les médicaments et traitement.\n\n💊 QUAND VOUS RECEVEZ MÉDICAMENT:\n\n✓ VÉRIFIER:\n□ Votre nom sur l'étiquette\n□ Nom du médicament (comprenez-vous?)\n□ Dosage (combien?)\n□ Fréquence (combien fois par jour?)\n□ Durée (combien de jours?)\n□ Instructions spéciales (avec manger? Sans?)\n\n❓ DEMANDER SI PAS SÛR:\n\"Je ne comprends pas.\"\n\"Pouvez-vous répéter s'il vous plaît?\"\n\"Comment exactement je prends?\"\n\"Quand arrêter?\"\n\n✓ PHARMACIEN DOIT VOUS EXPLIQUER:\n• How to take (swallow whole? With food?)\n• When to take (morning? Evening? Both?)\n• How long to take (3 days? 2 weeks?)\n• Side effects (what to watch for?)\n• Quand revenez pour suivi\n• Questions (\"Any questions?\")\n\n⚠️ IMPORTANT RULES:\n\n✓ À FAIRE:\n✓ Prendre EXACTEMENT comme prescrit\n✓ Terminer cours entier même si mieux\n✓ Prendre à l'heure (régulier)\n✓ Garder refroid/sec (selon instruction)\n✓ Éloigner enfants\n✓ Demander si effet secondaire\n✓ Revenez pour suivi\n✓ Parlez si penser allergique\n\n✗ À ÉVITER:\n✗ Ne pas arrêter tôt\n✗ Ne pas changer dosage\n✗ Ne pas partager avec autres\n✗ Ne pas prendre avec alcool (sauf permission)\n✗ Ne pas mélanger avec drogues\n✗ Ne pas ignorer side effects\n\n🔴 EFFETS SECONDAIRES GRAVES - REVENIR ASAP:\n• Difficulté respiratoire\n• Gonflement visage/gorge\n• Tachycardie (cœur très rapide)\n• Douleur thoracique\n• Très haute fièvre\n• Perte conscience\n• Saignement anormal\n\n🟡 EFFETS SECONDAIRES LÉGERS - MAIS RÉPORTEZ:\n• Nausée\n• Rash (petit)\n• Fatigue\n• Maux tête\n• Douleur estomac\n→ Généralement disparaissent\n→ Revenez si persistent ou pire\n\n🧪 ANALYSES & RÉSULTATS:\n\nQuand vous faites analyse (labo, test):\n✓ Comprendre pourquoi\n✓ Quand résultats (24-48h généralement)\n✓ Comment recevoir (phone? Email? Visite?)\n✓ Quoi faire si anormal\n\nRésultats:\n• Normal = OK, pas de problème\n• Anormal = Médecin explique\n• Critique = Appel immédiat\n\n📋 SUIVI:\n\nAprès consultation/traitement:\n• Quand revenir? (1 semaine? 1 mois?)\n• Comment savoir si mieux?\n• Qui appeler si problème?\n• Quoi faire si urgent?\n\n🏥 URGENCE:\n\nSignes d'urgence - Aller immédiatement:\n• Difficulté respiratoire\n• Douleur thoracique\n• Saignement important\n• Trauma sévère\n• Réaction allergique\n• Confusion/perte conscience\n• Très haute fièvre (>39°C)\n\nNE PAS ATTENDRE = VIE EN DANGER\n\n💡 CONSEIL: Lire étiquette. Poser questions. Prendre correctement. Santé meilleure!", Order = 4, Media = new() },
                new() { Title = "Sécurité Santé et Conseil Prévention", Content = "Rester en bonne santé et prévenir maladie.\n\n❤️ SANTÉ PRÉVENTIVE - IMPORTANCE:\n\n\"Prévention = meilleur traitement.\"\n\nAnciens: \"C'est cher aller chez médecin.\"\nMieux: \"C'est cher NE PAS aller chez médecin!\"\n\n✓ Mieux prévenir → jamais malade\n✓ Jamais malade → jamais dépenser\n✓ Jamais dépenser → plus d'argent\n✓ Plus d'argent → meilleure vie\n\n🏃 EXERCICE:\n\nCOMBIEN:\n• 30 minutes modéré, 5x/semaine\n• Ou 20 minutes intense, 3x/semaine\n\nQUOI:\n• Marche rapide\n• Jogging\n• Natation\n• Vélo\n• Danse\n• Sports\n• Travail physique\n\nBENEFITS:\n✓ Coeur fort\n✓ Poids normal\n✓ Énergie meilleure\n✓ Mental plus clair\n✓ Vivre plus longtemps\n✓ Meilleur sommeil\n\n🥗 NUTRITION:\n\nCLÉ: Équilibre\n\n✓ MANGER:\n• Fruits (3-5 portions/jour)\n• Légumes (3-5 portions/jour)\n• Proteine (viande, poisson, oeufs, beans)\n• Grain complet (riz brun, pain whole-wheat)\n• Eau (2 litres/jour)\n\n❌ LIMITER:\n• Sucre (bonbons, soda, gâteau)\n• Sel (réduit, pas aucun)\n• Gras saturé (viande grasse, huile)\n• Alcool (modération)\n• Aliments transformés\n\n⚖️ POIDS NORMAL:\n\n• Calculer BMI:\n  BMI = Poids (kg) / (Taille (m)²)\n  - < 18.5 = Underweight\n  - 18.5-24.9 = Normal\n  - 25-29.9 = Overweight\n  - ≥ 30 = Obésité\n\n• Si overweight: Parler à médecin\n  • Plan nutrition\n  • Exercice\n  • Support\n\n😴 SOMMEIL:\n\nIMPORTANCE:\n✓ Corps répare\n✓ Mental se repose\n✓ Immunité renforce\n✓ Humeur meilleure\n✓ Concentration mieux\n\nCOMBIEN:\n• 7-9 heures par nuit\n• Consécutif (pas fragmenté)\n\nTIPS:\n✓ Même heure chaque soir\n✓ Pas téléphone avant dormir\n✓ Chambre sombre/calme\n✓ Pas caféine après 14h\n✓ Relax avant lit (lire, méditation)\n\n🚭 FUMAGE:\n\nRISQUES:\n✗ Cancer poumon\n✗ Maladie coeur\n✗ COPD\n✗ Infection\n✗ Dent problème\n✗ Peau vieillit rapide\n✗ Moins d'argent\n\nBENEFITS ARRÊTER:\n✓ 1 jour: Respiration mieux\n✓ 1 mois: Cœur plus fort\n✓ 1 année: Risque cancer réduit 50%\n✓ 10 ans: Risque cancer = non-fumeur\n\nAIDES:\n• Médecin: Conseil + medicin (nicotine patch)\n• Support group\n• Apps/resources\n• Famille encourage\n\n🍺 ALCOOL:\n\nLIMITES SÛRES:\n• Homme: < 2 verres/jour\n• Femme: < 1 verre/jour\n• 2 jours/semaine sans alcool\n\nRISQUES ABUS:\n✗ Foie disease\n✗ Cancer\n✗ Brain damage\n✗ Accident/injury\n✗ Dependence\n✗ Family problem\n\n✓ STRESS:\n\nGestion stress importante:\n• Meditation (10 min/jour)\n• Yoga\n• Marche nature\n• Hobbies\n• Amis (support)\n• Parler problèmes\n• Rire (therapeutic!)\n• Relaxation\n\nSi stress chronique:\n→ Parler à médecin\n→ Thérapie utile\n→ Pas honteux\n\n💉 VACCINATIONS:\n\n✓ Importants pour:\n• Enfants (DPT, Rougeole, etc.)\n• Femmes enceinte (TTT)\n• Senior (Grippe, Pneumonie)\n• À risque (Hépatite B, HPV)\n\n✓ DÉPISTAGE RÉGULIER:\n• Tension artérielle: 1x/année\n• Poids/Taille: Régulier\n• Glucose (si diabète family): 1-3 ans\n• Cholesterol (si risque): Régulier\n• Cancer (women): Cervical/Breast screening\n• Prostate (men>50): Si risque\n\n💡 CONSEIL: Payer maintenant (prévention) vs payer plus tard (traitement). Prévention gagne toujours!", Order = 5, Media = new() },
                new() { Title = "Support Patient et Ressources", Content = "Vous n'êtes pas seul. Nous sommes ici pour aider.\n\n📞 COMMENT NOUS CONTACTER:\n\n✓ PENDANT HEURES (08h-17h):\n• Téléphone: [Numéro]\n• Email: info@brigademedicale.ci\n• En personne: [Adresse]\n• Chat (site web): Live support\n\n✓ APRÈS HEURES/URGENCE:\n• Emergency line: [24/24 Numéro]\n• Aller urgences directement\n• Appeler ambulance (15 ou 112)\n\n🆘 PROBLÈMES COURANTS - SOLUTIONS:\n\n❓ \"Je n'ai pas compris quelque chose.\"\n→ Appelez et demandez à quelqu'un vous expliquer\n→ Pas question bête\n→ C'est notre job de clarifier\n\n❓ \"Je n'ai pas d'argent pour paiement.\"\n→ Parlez au superviseur\n→ Options:\n  • Paiement partiel\n  • Plan paiement\n  • Referral assistance program\n→ Ne pas refusé soins\n\n❓ \"J'ai effet secondaire du médicament.\"\n→ STOP médicament\n→ Appelez médecin ASAP\n→ Aller ER si grave (difficulté respiratoire)\n→ Gardez bouteille (montrer médecin)\n\n❓ \"Je crois erreur dans mon dossier.\"\n→ Appeler et signaler\n→ Fournir détails\n→ Nous investiguerons\n→ Corriger si possible\n\n❓ \"Je n'ai pas compris instruction médecin.\"\n→ Rappeler pharmacien\n→ Demander clarification\n→ Écrire notes\n→ Garder numéro (pour future)\n\n💬 FEEDBACK & PLAINTES:\n\n✓ BON FEEDBACK:\n\"C'était excellent service. Staff friendly.\"\n→ Merci! Share avec superviseur\n→ Reward our team\n\n✓ PLAINTE:\n\"J'ai attendu très longtemps.\"\n→ Parlez au superviseur\n→ Expliquez problème\n→ Écouterons\n→ Chercher solution\n→ Sinon formal complaint (écrit)\n\nPROCESS COMPLAINT:\n1. Parler au lieu problème (résolution rapide)\n2. Écrire lettre (détails, demande)\n3. Envoyer à administration\n4. Réponse dans 7 jours\n5. Follow-up si non-résolu\n\n👥 RESSOURCES PATIENT:\n\n✓ DISPONIBLE:\n• Brochures santé (Au centre)\n• Videos educatif (Site web)\n• Hotline conseil (Phone)\n• Support group (Certaines conditions)\n• Counseling services (Mental health)\n• Nutritionist (Diet advice)\n• Physical therapy (Si besoin)\n\n✓ PATIENT RIGHTS:\nYous have right to:\n• Quality care\n• Respectful treatment\n• Privacy/confidentiality\n• Understand information\n• Second opinion\n• Refuse treatment\n• Access dossier\n• Safe environment\n• Report problems\n\n✓ SI VOUS AVEZ ASSURANCE:\n• Vérifier couverture\n• Apporter carte\n• Vérifier réseau (nous included?)\n• Comprendre co-pay\n• Savoir pre-approval (si needed)\n• Questions? Appeler assurance\n\n🌍 OPPORTUNITÉS FORMATION:\n\n✓ FORMATIONS GRATUITES:\n• Nutrition et santé\n• Gestion stress\n• Exercice\n• Condition spécifique (diabète, tension)\n• Prévention (smoking cessation)\n• Parenting (si applicable)\n\nParticiper:\n1. Appeler et demander\n2. Dates/heures\n3. Inscription (simple)\n4. Venir et apprendre\n5. Certificat (si wanted)\n\n💝 MERCI D'ÊTRE PATIENT:\n\n\"Merci de nous faire confiance avec votre santé.\nVotre sécurité et satisfaction = notre priorité.\nSi problème, dites-nous.\nSi merci, dites-nous aussi!\n\nNous sommes ici pour VOUS.\n\nVotre santé, c'est notre mission.\"\n\n💡 CONSEIL: Ne pas hesitez contacter. C'est pour ça nous sommes ici!", Order = 5, Media = new() }
